INSERT INTO public.products VALUES ('efce3594-f170-43b0-b37a-400b735b2163', '2000000167152', 'TAM-16715', 'Backwoods Blunt Authentic 5stk.', 'Backwoods cigars or backwoods blunts are specially imported from America to Switzerland. These special backwoods blunts are made in the Dominican Republic. The Backwoods Honey Berry are known from many celebrities who smoke these flavor cigars. Some like the backwood as it is, others like to add their own herbs to the backwoods, because they buy or rather have bought. You can easily roll these cigars apart and roll them back together again so that you have a perfect blunt. The Backwoods Honey Berry are very well packaged and are sewn airtight so that they do not dry out. The Backwoods Honey Berry are very well packaged and are sewn airtight so that they do not dry out.', 15.00, NULL, 1, NULL, 'Blunts & Wraps', 'artemis:papers-co/blunts/blunt-wrap,material:unbleached,path:blunt-wrap,brand:Backwoods,flavor:Natural', true, true, false, NULL, '16715', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=24fccc0b-3a3b-4fef-9901-db9157b9b8d6&w=414&h=414&ext=.jpg', '2026-06-30 15:10:49.999217+00', '2026-06-30 15:10:49.999222+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Backwoods", "flavor": "Natural", "length": "11 cm", "material": "unbleached"}', '{"Taste": "Natural", "Length": "11 cm", "Manufacturer": "Backwoods"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '24fccc0b-3a3b-4fef-9901-db9157b9b8d6', 'https://www.artemisluzern.ch/en/product/backwoods-blunt-authentic-5stk-16715', 'en', 'papers-co/blunts/blunt-wrap', false, NULL);
INSERT INTO public.products VALUES ('28f135a0-4e91-4391-b362-1f312ed97c7a', '2000000166896', 'TAM-16689', 'Cyclones Blunt Clear mit Filter Natural 1 Stk.', 'With transparent paper, conical pre-rolled blunt without taste. Comes wrinkle-free in a plastic tube.', 1.50, NULL, 1, NULL, 'Blunts & Wraps', 'artemis:papers-co/blunts/cyclones,brand:Cyclones,material:cellulose,material:unbleached,path:cyclones,flavor:Natural', true, true, false, NULL, '16689', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=c41f454a-801c-448d-a8c0-34b5750179ff&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.003483+00', '2026-06-30 15:10:50.003486+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Cyclones", "flavor": "Natural", "length": "11 cm", "material": "cellulose"}', '{"Taste": "Natural", "Length": "11 cm"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'c41f454a-801c-448d-a8c0-34b5750179ff', 'https://www.artemisluzern.ch/en/product/cyclones-blunt-clear-mit-filter-natural-1-stk-16689', 'en', 'papers-co/blunts/cyclones', false, NULL);
INSERT INTO public.products VALUES ('03df8138-b395-4bd0-a985-271c6e643fe2', '2000000237725', 'TAM-23772', 'G-Rollz Prerolled Blueberry Kookies  2 Stk.', 'Perfect enjoyment with CBD Blunt Cones from G-Rollz The Blunt Cones are 10.5 cm long and come in an airtight glass tube that contains two perfectly protected pieces. Thanks to the patented cone protection system from G-Rollz, the cones remain fresh and aromatic. They impress with first-class quality and a stylish look – ideal for headshop customers who value innovation and design. Whether it''s for relaxing evenings or special moments, these blunt cones take the smoking experience to the next level! High-quality blunt cones, developed in collaboration with cult stars Cheech and Chong Made from premium CBD flowers and canna-terpenes from the USA Tobacco and nicotine-free alternative for a pure smoking experience Flavor "Blueberry Biscuit" for sweet and fruity aroma variety', 4.90, NULL, 1, NULL, 'Blunts & Wraps', 'artemis:papers-co/blunts/g-rollz,path:g-rollz,brand:G-Rollz', true, true, false, NULL, '23772', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=ddffc9c6-b4a1-4efd-b2f5-bbde795aa82f&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.006704+00', '2026-06-30 15:10:50.006706+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "G-Rollz", "length": "10.5 cm"}', '{"Length": "10.5 cm", "Manufacturer": "G-Rollz"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'ddffc9c6-b4a1-4efd-b2f5-bbde795aa82f', 'https://www.artemisluzern.ch/en/product/g-rollz-prerolled-blueberry-kookies-2-stk-23772', 'en', 'papers-co/blunts/g-rollz', false, NULL);
INSERT INTO public.products VALUES ('de43a2f8-e9c4-44a9-baf8-717090427145', '2000000264066', 'TAM-26406', 'Chapo Blunt Hemp Wraps Cheri 2 stk.', 'Natural hemp wraps for the perfect blunt These high-quality hemp wraps are the ideal choice for anyone who wants to do without tobacco. Made from 100% natural hemp and completely free of tobacco, THC and nicotine, they offer a pure smoking experience. They are delivered in an airtight and resealable zip bag - so they stay fresh and aromatic. The wraps are perfect for headshop fans who value quality, naturalness and style. Try these flavorful wraps now and take your smoking ritual to the next level!', 2.50, NULL, 1, NULL, 'Blunts & Wraps', 'artemis:papers-co/blunts/juicy-blunt,material:hemp,path:juicy-blunt,brand:Chapo,flavor:Orange', true, true, false, NULL, '26406', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=9981c8f7-1245-4cf3-9837-8afd97f8faa5&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.008881+00', '2026-06-30 15:10:50.008883+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Chapo", "width": "5.4 cm", "flavor": "Orange", "length": "10.7 cm", "material": "hemp"}', '{"Taste": "Orange", "Width": "5.4 cm", "Length": "10.7 cm", "Manufacturer": "Chapo"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '9981c8f7-1245-4cf3-9837-8afd97f8faa5', 'https://www.artemisluzern.ch/en/product/chapo-blunt-hemp-wraps-cheri-2-stk-26406', 'en', 'papers-co/blunts/juicy-blunt', false, NULL);
