INSERT INTO public.products VALUES ('aa44ee40-219f-417c-8991-56cd43e42f7e', '2000000228457', 'TAM-22845', 'Elements King Size', 'Element Papers impress with the delicacy of the paper. Therefore, a good choice for every smoker! Elements are made of rice paper and burn with almost 0% ash. 100% pure rice paper with no chemicals, no pulp and NO hemp. To counter the trend and as a dedication to memories from the past, we have decided to revive the "elements" of smoking. Only a thin strip of natural sugar gum is used as a gluing point. The result is probably the best cigarette paper ever made by human hands.', 2.00, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/elements,brand:Elements,size:kingsize,path:elements', true, true, false, NULL, '22845', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=b348d6f0-d90c-4551-92cb-17508db2fa43&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.018324+00', '2026-06-30 15:10:50.018325+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Elements", "width": "5.1 cm", "length": "11 cm", "papierst_rke": "12 gr/m²", "raw_material": "Journey"}', '{"Width": "5.1 cm", "Length": "11 cm", "Raw material": "Journey", "Papierstärke": "12 gr/m²"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'b348d6f0-d90c-4551-92cb-17508db2fa43', 'https://www.artemisluzern.ch/en/product/elements-king-size-22845', 'en', 'papers-co/drehpapier/elements', false, NULL);
INSERT INTO public.products VALUES ('20efd458-ec72-4872-9d12-b6c30a34ea81', '2000000212999', 'TAM-21299', 'Gizeh DW kurz black', 'Extra fine leaves with a basis weight of 14 g/m² and a gum coating made of natural gum arabic, the sap of the acacia tree. The extra fine paper ensures pure and unadulterated enjoyment. It burns very slowly and goes out if you don''t pull on the self-rolled one. 2 rows with a total of 100 leaves are in a package with magnetic closure.', 1.80, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/gizeh,brand:Gizeh,path:gizeh', true, true, false, NULL, '21299', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=66526c21-4e7b-426b-bc45-8c9c20aba66c&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.019992+00', '2026-06-30 15:10:50.019994+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Gizeh", "width": "3.7 cm", "length": "6.8 cm", "papierst_rke": "14 gr/m²", "raw_material": "Journey", "number_of_sheets_per_piece": "100 Stk."}', '{"Width": "3.7 cm", "Length": "6.8 cm", "Raw material": "Journey", "Papierstärke": "14 gr/m²", "Number of sheets per piece": "100 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '66526c21-4e7b-426b-bc45-8c9c20aba66c', 'https://www.artemisluzern.ch/en/product/gizeh-dw-kurz-black-21299', 'en', 'papers-co/drehpapier/gizeh', false, NULL);
INSERT INTO public.products VALUES ('e04faa71-9eb2-4501-8350-19e4557dbb71', '2000000070117', 'TAM-7011', 'Greengo King Size', 'These unbleached tobacco papers from ''Greengo'' come from wood from sustainable forestry cultivation. The Greengo Papers are not only eye-catching because of their pretty packaging, they are also unbleached and made with paper from a sustainable source. FSC label included. The fact that they are also ultra-thin and have a beautiful spiral pattern embossing is just the cherry on top of the sundae. Greengo Papers for a green smoke! The full tobacco aroma can fully develop, unaffected by bleach, etc.', 1.70, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/greengo,brand:Greengo,size:kingsize,path:greengo', true, true, false, NULL, '7011', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=cef6cb01-be36-4ecd-85d3-4367959ae843&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.021689+00', '2026-06-30 15:10:50.021692+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Greengo", "width": "5.4 cm", "length": "10.8 cm", "papierst_rke": "13 gr/m²", "raw_material": "Wood"}', '{"Width": "5.4 cm", "Length": "10.8 cm", "Raw material": "Wood", "Papierstärke": "13 gr/m²"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'cef6cb01-be36-4ecd-85d3-4367959ae843', 'https://www.artemisluzern.ch/en/product/greengo-king-size-7011', 'en', 'papers-co/drehpapier/greengo', false, NULL);
INSERT INTO public.products VALUES ('846597e7-0b4b-4bfd-be02-e1deb05963e9', '2000000086170', 'TAM-8617', 'Juicy Jays King Size Cannabis', 'The Juicy Papers and Rolls -with Flavor- are made of hemp paper and are available in different flavors with the respective printed ones. They simply taste good and look cool. Juicy Papes products are known for their distinctive and intense taste. Through a special, cost-intensive process, Juicy products are provided with a wide variety of flavors, so that the product has a fresh and intense taste that can even be tasted when smoked. An excellent change from the conventional papers.', 1.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/juicy,brand:Juicy Jays,material:hemp,size:kingsize,path:juicy,flavor:Hemp', true, true, false, NULL, '8617', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=50720495-19c1-481c-ba14-bcb960fe94b2&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.023454+00', '2026-06-30 15:10:50.023456+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Juicy Jays", "width": "4.4 cm", "flavor": "Hemp", "length": "1.08 m", "material": "hemp", "raw_material": "Hemp", "number_of_sheets_per_piece": "33 Stk."}', '{"Taste": "Hemp", "Width": "4.4 cm", "Length": "1.08 m", "Manufacturer": "Juicy Jays", "Raw material": "Hemp", "Number of sheets per piece": "33 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '50720495-19c1-481c-ba14-bcb960fe94b2', 'https://www.artemisluzern.ch/en/product/juicy-jays-king-size-cannabis-8617', 'en', 'papers-co/drehpapier/juicy', false, NULL);
INSERT INTO public.products VALUES ('3b97e3da-6523-47de-85c7-0dc90f9d1ae3', '2000000236438', 'TAM-23643', 'Monkey King "King Size Slim & Filter" Blue Splash', 'Monkey King Papers – Aroma Edition: Fragrant papers with a real aroma effect The new Monkey King Papers with flavor variant really live up to their name: When you open the package, an intense, sweet scent immediately rises to your nose. No advertising ramblings – the aroma effect is immediately noticeable. The special highlight: After rubbing your buds, the typical weed smell often sticks to your fingers. With the Cookies Edition, you can easily cover this up. Rub your fingertips briefly on the packaging - and they take on the pleasant aroma scent of the papers. These papers not only offer high quality, but also a unique fragrance and user experience that clearly stands out from conventional papers. Perfect for those looking for that little bit extra.', 2.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/monkey-king,material:flax,size:kingsize,path:monkey-king,brand:Monkey King,flavor:Blaubeere', true, true, false, NULL, '23643', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=0630b9e9-584e-48a0-9e7d-3d2e26c65962&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.025133+00', '2026-06-30 15:10:50.025136+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Monkey King", "width": "4.4 cm", "flavor": "Blaubeere", "length": "10.8 cm", "material": "flax", "papierst_rke": "13 gr/m²", "raw_material": "Flax", "number_of_sheets_per_piece": "32 Stk."}', '{"Taste": "Blaubeere", "Width": "4.4 cm", "Length": "10.8 cm", "Manufacturer": "Monkey King", "Raw material": "Flax", "Papierstärke": "13 gr/m²", "Number of sheets per piece": "32 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '0630b9e9-584e-48a0-9e7d-3d2e26c65962', 'https://www.artemisluzern.ch/en/product/monkey-king-king-size-slim-filter-blue-splash-23643', 'en', 'papers-co/drehpapier/monkey-king', false, NULL);
INSERT INTO public.products VALUES ('1ce4f322-906c-4814-b9f7-9fa33ef07c33', '2000000082196', 'TAM-8219', 'OCB DW kurz Organic Hemp', 'Thin... really thin! OCB Papers is one of the most popular and well-known brands of French papers. A real hit in the thin paper sector. 100% natural made of hemp paper, vegan and unbleached. An absolutely new smoking experience!', 2.00, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/ocb,brand:OCB,material:hemp,material:organic,path:ocb', true, true, false, NULL, '8219', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=45c2666a-7395-4c90-b823-17eb69cb05cd&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.02682+00', '2026-06-30 15:10:50.026822+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "OCB", "width": "3.7 cm", "length": "6.7 cm", "material": "hemp", "papierst_rke": "14 gr/m²", "raw_material": "Hemp", "number_of_sheets_per_piece": "100 Stk."}', '{"Width": "3.7 cm", "Length": "6.7 cm", "Raw material": "Hemp", "Papierstärke": "14 gr/m²", "Number of sheets per piece": "100 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '45c2666a-7395-4c90-b823-17eb69cb05cd', 'https://www.artemisluzern.ch/en/product/ocb-dw-kurz-organic-hemp-8219', 'en', 'papers-co/drehpapier/ocb', false, NULL);
INSERT INTO public.products VALUES ('129d7be2-13be-4cfb-b3d8-1dfde74f4122', '2000000215778', 'TAM-21577', 'Raw KS Classic black Extra Fine', '100% natural and unbleached. An absolutely good smoking experience! Each package contains the organic RAW papers. Each package is printed on eco paper using a Japanese thermography process. The RAW Artesano Paperpack with paper, filter and mixing tray is the ideal companion for on the go. Its cover serves as a windbreak when turning as well as a tobacco pad. These papers burn very slowly and thus ensure long and easy smoking pleasure.', 1.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/raw,brand:RAW,size:kingsize,path:raw', true, true, false, NULL, '21577', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=c22fdab6-b098-454d-9d73-d698d8b53fe0&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.028473+00', '2026-06-30 15:10:50.028475+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "RAW", "width": "5.5 cm", "length": "10.9 cm", "papierst_rke": "13 gr/m²", "raw_material": "Journey", "number_of_sheets_per_piece": "32 Stk."}', '{"Width": "5.5 cm", "Length": "10.9 cm", "Manufacturer": "RAW", "Raw material": "Journey", "Papierstärke": "13 gr/m²", "Number of sheets per piece": "32 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'c22fdab6-b098-454d-9d73-d698d8b53fe0', 'https://www.artemisluzern.ch/en/product/raw-ks-classic-black-extra-fine-21577', 'en', 'papers-co/drehpapier/raw', false, NULL);
INSERT INTO public.products VALUES ('cf175a98-6082-4095-b11c-b21ca7ab5b28', '2000000039640', 'TAM-3964', 'Rizla DW kurz silver', 'Rizla is one of "the" traditional company from France for cigarette papers. Thin paper with good burning behavior is a must for Rizla. Rizla Papers do not contain impregnations to improve the smoldering ability. On the one hand, this has the consequence that the self-rolled one goes out faster if you don''t pull it regularly. The adhesive strip is made of pure gum arabic. Probably the thinnest papers from Rizla', 2.00, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/rizla,brand:Rizla,material:flax,path:rizla', true, true, false, NULL, '3964', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=b50a7f64-535e-4829-a445-8857df58ba27&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.077981+00', '2026-06-30 15:10:50.077983+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Rizla", "width": "3.7 cm", "length": "6.8 cm", "material": "flax", "papierst_rke": "12 gr/m²", "raw_material": "Flax", "number_of_sheets_per_piece": "100 Stk."}', '{"Width": "3.7 cm", "Length": "6.8 cm", "Raw material": "Flax", "Papierstärke": "12 gr/m²", "Number of sheets per piece": "100 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'b50a7f64-535e-4829-a445-8857df58ba27', 'https://www.artemisluzern.ch/en/product/rizla-dw-kurz-silver-3964', 'en', 'papers-co/drehpapier/rizla', false, NULL);
INSERT INTO public.products VALUES ('de1e3078-30f7-458d-a3e1-0278149ca19b', '2000000259604', 'TAM-25960', 'G-Rollz Banksy’s Graffiti Set 1  Lightly Dyed Pink KS Papers mit Bröselschale', 'Banksy''s graffiti on your papers – stylish and environmentally conscious! With the G-Rollz | Banksy''s Graffiti Set 1 you get Banksy''s iconic street art on your paper and tips booklets. A practical extra: Each booklet contains a foldable tray - perfect for on the go! The sustainable G-Rollz products combine cool design with environmental awareness. Check the authenticity of each booklet by scanning the verification code. Dimensions of the papers: length 11 cm, width 4.4 cm. A must-have for every smart shooting session! This series surprises with two different subjects that are chosen at random – surprise guaranteed. Per booklet you get: 50 unbleached, chlorine- and non-GMO papers 50 vegan tips A bamboo stick for darning', 3.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/ziggis,size:kingsize,path:ziggis,brand:G-Rollz', true, true, false, NULL, '25960', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=f237c8ee-9d12-4053-9eb4-178d07e6926e&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.038777+00', '2026-06-30 15:10:50.038779+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "G-Rollz", "width": "4.4 cm", "length": "10.8 cm", "raw_material": "Journey"}', '{"Width": "4.4 cm", "Length": "10.8 cm", "Manufacturer": "G-Rollz", "Raw material": "Journey"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'f237c8ee-9d12-4053-9eb4-178d07e6926e', 'https://www.artemisluzern.ch/en/product/g-rollz-banksys-graffiti-set-1-lightly-dyed-pink-ks-papers-mit-broeselschale-25960', 'en', 'papers-co/drehpapier/ziggis', true, NULL);
INSERT INTO public.products VALUES ('4b0fa52e-8f8b-4282-adab-8e17d664b8c4', '2000000262987', 'TAM-26298', 'Highstore 20 Meter Premium Smoking Rolls', '?? 20 Meter Endless Papers Rolls – Ultra Thin Premium Quality ?? With the Endless Papers Rolls you get the longest papers in Switzerland: 20 meters of ultra-thin premium paper, perfect for endless sessions and maximum enjoyment. Thanks to its length, you decide how much you want to spin – with no limits, no refilling. 20 meters long – the longest smoking rolls in Switzerland Ultra Thin Paper (12.5 g/m²) – slow, even burning 44 mm width – ideal for custom turning Tasteless – pure enjoyment without annoying paper taste 16 rolls per box – ideal for heavy users or head shops Stylish design – eye-catching and modern in a high-store look The Endless Papers Rolls set new standards in terms of style and functionality. Whether for long sessions, creative creations or everyday use: With these smoking rolls you are at the forefront. Discover Swiss quality for real connoisseurs!', 4.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/rips,brand:Smoking,path:rips,brand:Highstore', true, true, false, NULL, '26298', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=25995212-1830-4534-a388-78166b4f9ea2&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.030144+00', '2026-06-30 15:10:50.030146+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Smoking", "width": "4.4 cm", "length": "20 m", "papierst_rke": "12.5 gr/m²", "raw_material": "Journey"}', '{"Width": "4.4 cm", "Length": "20 m", "Manufacturer": "Highstore", "Raw material": "Journey", "Papierstärke": "12.5 gr/m²"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '25995212-1830-4534-a388-78166b4f9ea2', 'https://www.artemisluzern.ch/en/product/highstore-20-meter-premium-smoking-rolls-26298', 'en', 'papers-co/drehpapier/rips', false, NULL);
INSERT INTO public.products VALUES ('c66a00b1-64f9-4a2b-b42f-3a528e7f8e93', '2000000039626', 'TAM-3962', 'Rizla DW kurz orange', 'Rizla is one of "the" traditional company from France for cigarette papers. Thin paper with good burning behavior is a must for Rizla. Rizla Papers do not contain impregnations to improve the smoldering ability. On the one hand, this has the consequence that the self-rolled one goes out faster if you don''t pull it regularly. The adhesive strip is made of pure gum arabic. The Rizzla Orange are ideal if you don''t like the fact that your self-rolled cigarettes are constantly extinguished.', 2.00, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/rizla,brand:Rizla,material:flax,path:rizla', true, true, false, NULL, '3962', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=9a2dee0e-fc88-47ab-80ca-a5128aa8bf3d&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.031841+00', '2026-06-30 15:10:50.031842+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Rizla", "width": "3.7 cm", "length": "6.8 cm", "material": "flax", "papierst_rke": "14 gr/m²", "raw_material": "Flax", "number_of_sheets_per_piece": "100 Stk."}', '{"Width": "3.7 cm", "Length": "6.8 cm", "Raw material": "Flax", "Papierstärke": "14 gr/m²", "Number of sheets per piece": "100 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '9a2dee0e-fc88-47ab-80ca-a5128aa8bf3d', 'https://www.artemisluzern.ch/en/product/rizla-dw-kurz-orange-3962', 'en', 'papers-co/drehpapier/rizla', false, NULL);
INSERT INTO public.products VALUES ('b145bffb-ea54-4336-b6ac-fc50d966321a', '2000000045054', 'TAM-4505', 'RS Rolls blau', 'The RS Rolls are very fine, wafer-thin cigarette papers made of rice with watermarks and natural gums, they have been around since 1984 and are produced in Italy.', 1.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/rs-rolls,path:rs-rolls', true, true, false, NULL, '4505', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=219628c5-49dc-4087-85a4-f9befb2d34bb&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.033708+00', '2026-06-30 15:10:50.03371+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"width": "5.2 cm", "length": "3.5 m", "papierst_rke": "14 gr/m²", "raw_material": "Journey"}', '{"Width": "5.2 cm", "Length": "3.5 m", "Raw material": "Journey", "Papierstärke": "14 gr/m²"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '219628c5-49dc-4087-85a4-f9befb2d34bb', 'https://www.artemisluzern.ch/en/product/rs-rolls-blau-4505', 'en', 'papers-co/drehpapier/rs-rolls', false, NULL);
INSERT INTO public.products VALUES ('84a1d451-e756-4268-9040-7d7157b613b8', '2000000102740', 'TAM-10274', 'Shine 24K Gold Cone', 'The Shine 24K Gold Cones are an invention from the USA and are undoubtedly one of the most unusual items in our range. Gold is the status symbol par excellence and is widely regarded as a sign of prosperity. But not everyone is lucky enough to be rich. If you really want to make a splash, the Shine 24K Gold Cones are a real luxury accessory. The Shine 24K Gold Cones are great for making special moments (milestone birthday, New Year''s Eve, etc.) finally unforgettable. Give it to yourself or a friend and enjoy the unique feeling of smoking gold "in the pipe". The Shine 24K Gold Rolling Papers are coated with 24-carat gold on the outside. The gold used has 24 carats, because it ultimately ends up in your organism and coarse impurities (silver + copper) would pose a health hazard. The fine gold used could even be eaten... According to the statements of the first test smokers, the Gold Papers burn very slowly and evenly. Order a pack of Shine 24K Gold Cones today and you are guaranteed to be one of the first smokers in Switzerland to gild your mixture! The Shine 24K Gold Cones are already rolled, which means: just fill them and off you go.', 14.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/shine-gold,path:shine-gold', true, true, false, NULL, '10274', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=e1f7bde5-8ad6-4a70-83ae-859ff9d9a197&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.035436+00', '2026-06-30 15:10:50.035438+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"length": "11 cm", "raw_material": "Gold"}', '{"Length": "11 cm", "Raw material": "Gold"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'e1f7bde5-8ad6-4a70-83ae-859ff9d9a197', 'https://www.artemisluzern.ch/en/product/shine-24k-gold-cone-10274', 'en', 'papers-co/drehpapier/shine-gold', false, NULL);
INSERT INTO public.products VALUES ('5e56d0e9-f779-42ad-877f-a770c84bd3ee', '2000000184203', 'TAM-18420', 'Breit Dollar King Size', '''Breit'' Papers ''Dollar'' in king size format in the best ultra thin quality with natural gum coating. Uniform and slow, as well as almost residue-free combustion.', 1.30, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/smoking,brand:Smoking,size:kingsize,path:smoking', true, true, false, NULL, '18420', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=a4177b3c-2507-443a-95be-fb6f7fd968ed&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.037108+00', '2026-06-30 15:10:50.037109+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Smoking", "width": "5.2 cm", "length": "10.8 cm", "papierst_rke": "13 gr/m²", "raw_material": "Journey", "number_of_sheets_per_piece": "32 Stk."}', '{"Width": "5.2 cm", "Length": "10.8 cm", "Raw material": "Journey", "Papierstärke": "13 gr/m²", "Number of sheets per piece": "32 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'a4177b3c-2507-443a-95be-fb6f7fd968ed', 'https://www.artemisluzern.ch/en/product/breit-dollar-king-size-18420', 'en', 'papers-co/drehpapier/smoking', false, NULL);
INSERT INTO public.products VALUES ('109834d0-fa18-41a6-bec1-368235912464', '2000000040523', 'TAM-4052', 'Gummihülle für Smoking King Size Bob Marley', 'Gumi sleeve fits on all paper with king size format.', 5.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier-dosen,brand:Smoking,size:kingsize,brand:Tamar', true, true, false, NULL, '4052', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=5b5a7028-2ccb-4a04-a212-d39da82b1ebc&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.040565+00', '2026-06-30 15:10:50.040567+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Smoking"}', '{"Manufacturer": "Tamar"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '5b5a7028-2ccb-4a04-a212-d39da82b1ebc', 'https://www.artemisluzern.ch/en/product/gummihuelle-fuer-smoking-king-size-bob-marley-4052', 'en', 'papers-co/drehpapier-dosen', true, NULL);
INSERT INTO public.products VALUES ('5ee14df8-7715-4891-9daa-bcf4117f635c', '2000000237336', 'TAM-23733', 'Air Filter  XHALE Buddy Mushroom grün', 'Discreet smoking made easy Forget about conspicuous clouds of cannabis that could attract the attention of neighbors or landlords. With this innovative air filter, you can exhale your smoke directly into the stylish mushroom. Thanks to a four-stage HEPA filter with nano-activated carbon, fragrances are effectively absorbed, and odor-free air flows out discreetly. Perfect for relaxed weed without unpleasant looks - on the go, at home or in the hotel. Technical highlights: 4-stage HEPA filter (100% recyclable) removes even the finest smoke particles ( Ergonomic mouthpiece made of food-grade silicone Portable and humorous mushroom design (6.35 cm diameter, 10.4 cm length) Durable filter for up to 500 puffs, easily replaceable (Item no. 453401-80) Protect yourself and others from secondhand smoke – environmentally friendly, efficient and in style!', 14.90, NULL, 1, NULL, 'Filters & Tips', 'artemis:papers-co/filter/diverse,path:diverse,brand:XHALE,color:Green', true, true, false, NULL, '23733', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=0320c7c5-c16c-42c0-9a6f-0b7017e94c4b&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.042269+00', '2026-06-30 15:10:50.042271+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "XHALE", "color": "Green", "length": "9 cm", "diameter": "6 cm"}', '{"Color": "Green", "Length": "9 cm", "Diameter": "6 cm", "Manufacturer": "XHALE"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '0320c7c5-c16c-42c0-9a6f-0b7017e94c4b', 'https://www.artemisluzern.ch/en/product/air-filter-xhale-buddy-mushroom-gruen-23733', 'en', 'papers-co/filter/diverse', true, NULL);
