INSERT INTO public.products VALUES ('f3db0f7b-745a-4397-84a6-9e1f0b8fb1de', '2000000045047', 'TAM-4504', 'RS Rolls grün', 'The RS Rolls are very fine, wafer-thin cigarette papers made of rice with watermarks and natural gums, they have been around since 1984 and are produced in Italy.', 2.00, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/rs-rolls,path:rs-rolls', true, true, false, NULL, '4504', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=6e8f74d7-598e-4cb8-8e58-042f31755ac3&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.079639+00', '2026-06-30 15:10:50.079641+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"width": "4.5 cm", "length": "3.5 m", "papierst_rke": "14 gr/m²", "raw_material": "Journey"}', '{"Width": "4.5 cm", "Length": "3.5 m", "Raw material": "Journey", "Papierstärke": "14 gr/m²"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '6e8f74d7-598e-4cb8-8e58-042f31755ac3', 'https://www.artemisluzern.ch/en/product/rs-rolls-gruen-4504', 'en', 'papers-co/drehpapier/rs-rolls', true, NULL);
INSERT INTO public.products VALUES ('de4b3c9e-0d3e-4a39-bb79-a4f7bd59fb6c', '2000000221212', 'TAM-22121', 'Black Leaf Füllhilf-Konsole Dollar', 'For all fans of cones: Very practical rolling tray from Black Leaf® especially for filling cones. And since cone fans are already a little lazy, you can finish two cones in one go! It''s really easy: Simply unfold the rolling tray, attach the accessories to the side, select the cone holder according to the cone size and load it with the appropriate cone. Insert the holders and cone into the openings of the tray, making sure that they are flush. Grind the herbs, mix with tobacco or a herbal mixture if necessary and tip onto the tray. Sweep herbs or mixture into the cone openings with the enclosed small whisk and press down with the cone maker tool. Then grasp the black holder and push it out from bottom to top and push out the filled cone - the perfect jay is ready! If you only want to fill a cone or use the Rolling Tray for conventional rolling or building, you can close the holes in the Rolling Tray with the sealing caps that are also included. The trays are printed with our popular Black Leaf® motifs.', 22.00, NULL, 1, NULL, 'Cigarette Tubes', 'artemis:papers-co/joint-huelsen-cones,brand:Cones,brand:Black Leaf,material:Sheet metal', true, true, false, NULL, '22121', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=553ddcf2-27d1-4735-acba-a4c32ff2a226&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.047324+00', '2026-06-30 15:10:50.047326+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Cones", "width": "9.8 cm", "length": "21.5 cm", "material": "Sheet metal"}', '{"Width": "9.8 cm", "Length": "21.5 cm", "Material": "Sheet metal", "Manufacturer": "Black Leaf"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '553ddcf2-27d1-4735-acba-a4c32ff2a226', 'https://www.artemisluzern.ch/en/product/black-leaf-fuellhilf-konsole-dollar-22121', 'en', 'papers-co/joint-huelsen-cones', true, NULL);
INSERT INTO public.products VALUES ('367b4edc-a12a-4b54-91fd-4a11d2b16ce0', '2000000197890', 'TAM-19789', 'Joint-Pack Amarantholz 110mm', 'Joints feel most comfortable in these beautifully natural, handmade joint tubes made of real wood from Black Leaf®. And are safely protected from moisture, crushing, crumbling and prying eyes. Precious wood from sustainable cultivation discreet Black Leaf engraving Flavour enhancement through wood aromas', 14.90, NULL, 1, NULL, 'Pre-rolled', 'artemis:papers-co/jointpack,material:wood-pulp,material:unbleached,measure:110mm,brand:Black Leaf,color:Brown,material:Wood', true, true, false, NULL, '19789', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=80cf5250-e971-46de-b246-c6cc2b5f73e1&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.049005+00', '2026-06-30 15:10:50.049007+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Black Leaf", "color": "Brown", "length": "11 cm", "measure": "110mm", "diameter": "1.6 cm", "material": "wood-pulp"}', '{"Color": "Brown", "Length": "11 cm", "Diameter": "1.6 cm", "Material": "Wood", "Manufacturer": "Black Leaf"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '80cf5250-e971-46de-b246-c6cc2b5f73e1', 'https://www.artemisluzern.ch/en/product/joint-pack-amarantholz-110mm-19789', 'en', 'papers-co/jointpack', false, NULL);
INSERT INTO public.products VALUES ('07b0425c-6a29-4f6d-86de-d9e7e313445f', '2000000231556', 'TAM-23155', 'Zigaretten-Hülsen 1000er Korona', 'Korona Cigarette Tubes - Box - 1000 Pieces Korona 550 box cigarette tubes made of high quality material at the best prices! The Korona tubes are individually removable and are perfect for rolling and stuffing cigarettes.', 14.90, NULL, 1, NULL, 'Cigarette Tubes', 'artemis:papers-co/zigaretten-huelsen,size:8mm,brand:Korona', true, true, false, NULL, '23155', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=3053f44a-f01f-4da8-be1d-ac4bd5ced88c&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.050692+00', '2026-06-30 15:10:50.050694+00', NULL, NULL, NULL, 'tobacco_nicotine', 'Papers & Co', 'class:tobacco_nicotine', true, '{"size": "8mm", "brand": "Korona", "length": "8 cm", "diameter": "8 mm", "number_of_cigarettes": "1000 Stk."}', '{"Length": "8 cm", "Diameter": "8 mm", "Manufacturer": "Korona", "Number of cigarettes": "1000 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '3053f44a-f01f-4da8-be1d-ac4bd5ced88c', 'https://www.artemisluzern.ch/en/product/zigaretten-huelsen-1000er-korona-23155', 'en', 'papers-co/zigaretten-huelsen', true, NULL);
INSERT INTO public.products VALUES ('403e109f-0220-452f-b2a1-e6be5221a5f7', '2000000263311', 'TAM-26331', 'Backwoods Blunt Bold 5 stk.', 'Intense aroma and full-bodied taste Backwoods Bold is the ideal choice for those looking for a bold and distinctive smoking experience. With its rustic look and intense tobacco notes, this variety delivers the typical backwoods character in an even more expressive variant. Earthy-spicy nuances give it an authentic profile that is particularly suitable for experienced connoisseurs. Rustic look and fresh pack for freshness As with all Backwoods cigars, the natural tobacco leaf provides the unmistakable look. Packed in a practical Fresh Pack, aroma and moisture are optimally preserved - perfect for on the go or in the humidor. Length: 11 cm Taste: sweet, spicy Ideal for quiet sessions or the evening Backwoods Bold offers you a pleasant but intense smoke with a full body – just right if you''re looking for more depth and character!', 16.00, NULL, 1, NULL, 'Blunts & Wraps', 'artemis:papers-co/blunts/blunt-wrap,path:blunt-wrap,brand:Backwoods,flavor:earthy', true, true, false, NULL, '26331', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=422c6a56-a43f-4795-913f-db4be1f03e0f&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.052341+00', '2026-06-30 15:10:50.052343+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Backwoods", "flavor": "earthy", "length": "11 cm"}', '{"Taste": "earthy", "Length": "11 cm", "Manufacturer": "Backwoods"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '422c6a56-a43f-4795-913f-db4be1f03e0f', 'https://www.artemisluzern.ch/en/product/backwoods-blunt-bold-5-stk-26331', 'en', 'papers-co/blunts/blunt-wrap', false, NULL);
INSERT INTO public.products VALUES ('d4297c15-f5c6-4c50-aeb5-b4379ba7795f', '2000000108827', 'TAM-10882', 'Cyclones Blunt Clear mit Filter Tiki Tango Coconut 1 Stk.', 'With transparent paper conical pre-twisted blunt with Taste. Comes wrinkle-free in a plastic tube.', 1.50, NULL, 1, NULL, 'Blunts & Wraps', 'artemis:papers-co/blunts/cyclones,brand:Cyclones,material:cellulose,path:cyclones,flavor:Coconut', true, true, false, NULL, '10882', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=668c3ebd-5fb1-46f7-b53b-f015c612520d&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.054123+00', '2026-06-30 15:10:50.054126+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Cyclones", "flavor": "Coconut", "length": "11 cm", "material": "cellulose"}', '{"Taste": "Coconut", "Length": "11 cm"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '668c3ebd-5fb1-46f7-b53b-f015c612520d', 'https://www.artemisluzern.ch/en/product/cyclones-blunt-clear-mit-filter-tiki-tango-coconut-1-stk-10882', 'en', 'papers-co/blunts/cyclones', false, NULL);
INSERT INTO public.products VALUES ('adc365aa-40cf-41e2-964a-5225dc3100aa', '2000000246130', 'TAM-24613', 'G-Rollz Prerolled Mango  2 Stk.', 'Unique smoking experience and full aroma Enjoy an intense and aromatic smoking experience with the G-Rollz Terpene Infused Blunt Cones. These high-quality blunt cones are made from CBD flowers from the USA and enriched with premium canna-terpenes that provide an unadulterated taste and distinctive aroma. Tobacco and nicotine free: 100% free of tobacco and nicotine - ideal for those who prefer natural enjoyment without harmful additives. Alternative to traditional blunts, without compromising on taste. Innovative packaging and protection: Packaged in airtight glass tubes, freshness and aroma are optimally preserved. The patented G-Rollz Cone Protector protects against damage during transport and makes filling easy. King size for extra enjoyment: Length: 10.5 cm - perfect for long-lasting smoking pleasure with your favorite herbal blends. Two Blunt Cones per pack – convenient, fresh and ready to use. Positive features: Infused with USA ''Canna'' terpenes: Intense flavor and aroma. Tobacco and nicotine free: Pure enjoyment without harmful additives. Airtight packaging: freshness and aroma are preserved. Patented Cone Protector: Protection against damage and easy filling. King Size: Ideal for long-lasting smoking pleasure. Shelf-ready display: 12 glass tube sales unit, ideal for retail. Details: Material: Sheet material Packing: Glass tube Size: King Size Unit: 1 Carton: 12 tubes and 24 blunts', 4.90, NULL, 1, NULL, 'Blunts & Wraps', 'artemis:papers-co/blunts/g-rollz,path:g-rollz,brand:G-Rollz', true, true, false, NULL, '24613', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=174a06fc-93a6-4769-942e-208f65fd6d7a&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.055858+00', '2026-06-30 15:10:50.05586+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "G-Rollz", "length": "10.5 cm"}', '{"Length": "10.5 cm", "Manufacturer": "G-Rollz"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '174a06fc-93a6-4769-942e-208f65fd6d7a', 'https://www.artemisluzern.ch/en/product/g-rollz-prerolled-mango-2-stk-24613', 'en', 'papers-co/blunts/g-rollz', false, NULL);
INSERT INTO public.products VALUES ('5b59a776-e160-4360-9443-75be2fd85417', '2000000264059', 'TAM-26405', 'Chapo Blunt Hemp Wraps El Patron 2 stk.', 'Natural hemp wraps for the perfect blunt These high-quality hemp wraps are the ideal choice for anyone who wants to do without tobacco. Made from 100% natural hemp and completely free of tobacco, THC and nicotine, they offer a pure smoking experience. They are delivered in an airtight and resealable zip bag - so they stay fresh and aromatic. The wraps are perfect for headshop fans who value quality, naturalness and style. Try these flavorful wraps now and take your smoking ritual to the next level!', 2.50, NULL, 1, NULL, 'Blunts & Wraps', 'artemis:papers-co/blunts/juicy-blunt,material:hemp,path:juicy-blunt,brand:Chapo,flavor:Orange', true, true, false, NULL, '26405', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=b91178fa-76f5-460f-b69b-13ec80d56826&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.057653+00', '2026-06-30 15:10:50.057654+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Chapo", "width": "5.4 cm", "flavor": "Orange", "length": "10.7 cm", "material": "hemp"}', '{"Taste": "Orange", "Width": "5.4 cm", "Length": "10.7 cm", "Manufacturer": "Chapo"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'b91178fa-76f5-460f-b69b-13ec80d56826', 'https://www.artemisluzern.ch/en/product/chapo-blunt-hemp-wraps-el-patron-2-stk-26405', 'en', 'papers-co/blunts/juicy-blunt', false, NULL);
INSERT INTO public.products VALUES ('3013c07b-0f98-4518-8420-f39d8d880046', '2000000041438', 'TAM-4143', 'Juicy Jays Super Blunt Tropical Passion  23cm  1 Stk.', 'Huge blunt 23cm long and already brought into shape. Airtight packed in aluminum paper and again in a sturdy cardboard box. The best Super Blunt in the World!', 8.90, NULL, 1, NULL, 'Blunts & Wraps', 'artemis:papers-co/blunts/super-blunts,brand:Juicy Jays,measure:23cm,path:super-blunts,flavor:Fruchtmix', true, true, false, NULL, '4143', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=12a9db4b-92f7-4858-90d5-d4b09dd00ce1&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.059357+00', '2026-06-30 15:10:50.059359+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Juicy Jays", "flavor": "Fruchtmix", "length": "23 cm", "measure": "23cm"}', '{"Taste": "Fruchtmix", "Length": "23 cm", "Manufacturer": "Juicy Jays"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '12a9db4b-92f7-4858-90d5-d4b09dd00ce1', 'https://www.artemisluzern.ch/en/product/juicy-jays-super-blunt-tropical-passion-23cm-1-stk-4143', 'en', 'papers-co/blunts/super-blunts', false, NULL);
INSERT INTO public.products VALUES ('d6dee67d-ab29-4ed6-81d2-f1088a5fcf1a', '2000000229409', 'TAM-22940', 'Drehmaschine Futurola Design 110mm', 'This Futurola Design lathe in king size length is almost an icon of machine-assisted cigarette production by hand The Futorola is made of plastic and the look of the lathe is absolutely stylish. Including free tamper with herb shovel', 19.90, NULL, 1, NULL, 'Rolling Machines', 'artemis:papers-co/drehmaschinen,measure:110mm,brand:X4', true, true, false, NULL, '22940', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=11914548-7c31-4e94-8647-03b23df73c29&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.061032+00', '2026-06-30 15:10:50.061033+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"type": "conical", "brand": "X4", "length": "11 cm", "measure": "110mm", "number_of_pieces": "1 Stk."}', '{"Type": "conical", "Length": "11 cm", "Manufacturer": "X4", "Number of pieces": "1 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '11914548-7c31-4e94-8647-03b23df73c29', 'https://www.artemisluzern.ch/en/product/drehmaschine-futurola-design-110mm-22940', 'en', 'papers-co/drehmaschinen', false, NULL);
INSERT INTO public.products VALUES ('c56a15dc-7308-4203-acc3-018d79a523b3', '2000000205038', 'TAM-20503', 'Dollar King Size + Filter', 'Decadence... Yes, please! Long papers in super king size format with 100 US dollar motif. Benjamin Franklin is one of the founding fathers of the United States of America, with which he even made it onto the 100 dollar bill. Was he also a stoner? No idea! The Super King Size Papers are made of unbleached hemp paper and printed with soy ink. This is how burning dollars is really fun!!', 4.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/diverse,material:hemp,size:kingsize,path:diverse,brand:Powerpapers', true, true, false, NULL, '20503', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=5113c7ff-a8b3-4300-81de-254fdebe6c60&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.06271+00', '2026-06-30 15:10:50.062712+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Powerpapers", "width": "5.4 cm", "length": "11 cm", "material": "hemp", "raw_material": "Hemp", "number_of_sheets_per_piece": "12 Stk."}', '{"Width": "5.4 cm", "Length": "11 cm", "Manufacturer": "Powerpapers", "Raw material": "Hemp", "Number of sheets per piece": "12 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '5113c7ff-a8b3-4300-81de-254fdebe6c60', 'https://www.artemisluzern.ch/en/product/dollar-king-size-filter-20503', 'en', 'papers-co/drehpapier/diverse', false, NULL);
INSERT INTO public.products VALUES ('fa7b5a31-ef52-4cf9-a2b2-0667de9599f4', '2000000232225', 'TAM-23222', 'Elements King Size Phantom Slim', 'Elements Phantom King Size Slim – Ultra-thin, exclusive & almost invisible Experience the purest smoking experience with the Elements Phantom King Size Slim - probably the thinnest papers from Elements. Around 20% thinner than standard models, they burn extra slowly and evenly and are almost tasteless - for unadulterated enjoyment of your herbs or tobacco mixture. This exclusive special edition is only produced in small editions and is currently available almost exclusively in the USA - a real collector''s item for paper fans. Highlights: Ultra-thin rice paper (approx. 20% thinner than standard) Exclusive Limited Edition – hard to get King Size Slim Format (110 × 44 mm) Almost tasteless - ideal for pure enjoyment Natural Acacia Gum Slow, even burning without canoeing Made in Spain – Original Elements quality', 4.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/elements,brand:Elements,size:kingsize,path:elements', true, true, false, NULL, '23222', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=7d991f19-d513-465d-9d7b-8aef6b900a72&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.064349+00', '2026-06-30 15:10:50.064351+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Elements", "width": "4.4 cm", "length": "11 cm", "papierst_rke": "10 gr/m²", "raw_material": "Journey"}', '{"Width": "4.4 cm", "Length": "11 cm", "Raw material": "Journey", "Papierstärke": "10 gr/m²"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '7d991f19-d513-465d-9d7b-8aef6b900a72', 'https://www.artemisluzern.ch/en/product/elements-king-size-phantom-slim-23222', 'en', 'papers-co/drehpapier/elements', false, NULL);
INSERT INTO public.products VALUES ('a22b4a4b-aeb6-4b02-96d5-039c15652b28', '2000000216690', 'TAM-21669', 'Gizeh King Size', 'Extra fine, leaflets with a basis weight of 14.0 g/m² and a gum coating made of natural gum arabic, the sap of the acacia tree. The extra fine paper ensures pure and unadulterated enjoyment., the width corresponds to the King Size Slim format. The paper burns very slowly and goes out if you don''t pull the self-rolled one. And of course, the packs are fully recyclable.', 1.40, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/gizeh,brand:Gizeh,material:flax,size:kingsize,path:gizeh', true, true, false, NULL, '21669', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=499892cb-b3bd-43e3-a78f-87a893ca3c64&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.066057+00', '2026-06-30 15:10:50.066059+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Gizeh", "width": "5.2 cm", "length": "11 cm", "material": "flax", "papierst_rke": "14 gr/m²", "raw_material": "Flax", "number_of_sheets_per_piece": "34 Stk."}', '{"Width": "5.2 cm", "Length": "11 cm", "Raw material": "Flax", "Papierstärke": "14 gr/m²", "Number of sheets per piece": "34 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '499892cb-b3bd-43e3-a78f-87a893ca3c64', 'https://www.artemisluzern.ch/en/product/gizeh-king-size-21669', 'en', 'papers-co/drehpapier/gizeh', false, NULL);
INSERT INTO public.products VALUES ('c6f09ccc-a71f-43f2-b5b5-04519467dd6b', '2000000123110', 'TAM-12311', 'Greengo King Size Slim', 'These unbleached tobacco papers from ''Greengo'' come from wood from sustainable forestry cultivation. The Greengo Papers are not only eye-catching because of their pretty packaging, they are also unbleached and made with paper from a sustainable source. FSC label included. The fact that they are also ultra-thin and have a beautiful spiral pattern embossing is just the cherry on top of the sundae. Greengo Papers for a green smoke! The full tobacco aroma can fully develop, unaffected by bleach, etc.', 1.70, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/greengo,brand:Greengo,size:kingsize,path:greengo', true, true, false, NULL, '12311', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=2f84468c-4969-4051-bdc9-a74db880c64d&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.067725+00', '2026-06-30 15:10:50.067727+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Greengo", "width": "4 cm", "length": "10.8 cm", "papierst_rke": "13 gr/m²", "raw_material": "Wood", "number_of_sheets_per_piece": "33 Stk."}', '{"Width": "4 cm", "Length": "10.8 cm", "Raw material": "Wood", "Papierstärke": "13 gr/m²", "Number of sheets per piece": "33 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '2f84468c-4969-4051-bdc9-a74db880c64d', 'https://www.artemisluzern.ch/en/product/greengo-king-size-slim-12311', 'en', 'papers-co/drehpapier/greengo', false, NULL);
INSERT INTO public.products VALUES ('7e277abe-8996-4fef-aa15-24963b0289de', '2000000042350', 'TAM-4235', 'Juicy Jays Rolls Apple', 'The Juicy Papers and Rolls -with Flavor- are made of hemp paper and are available in different flavors with the respective printed ones. They simply taste good and look cool. Juicy Papes products are known for their distinctive and intense taste. Through a special, cost-intensive process, Juicy products are provided with a wide variety of flavors, so that the product has a fresh and intense taste that can even be tasted when smoked. An excellent change from the conventional papers.', 3.20, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/juicy,brand:Juicy Jays,material:hemp,path:juicy,flavor:Apple', true, true, false, NULL, '4235', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=8fc2c197-00bb-4ac8-8815-e5f9e418c737&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.069439+00', '2026-06-30 15:10:50.069441+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Juicy Jays", "width": "5.4 cm", "flavor": "Apple", "length": "5 m", "material": "hemp", "raw_material": "Hemp"}', '{"Taste": "Apple", "Width": "5.4 cm", "Length": "5 m", "Manufacturer": "Juicy Jays", "Raw material": "Hemp"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '8fc2c197-00bb-4ac8-8815-e5f9e418c737', 'https://www.artemisluzern.ch/en/product/juicy-jays-rolls-apple-4235', 'en', 'papers-co/drehpapier/juicy', false, NULL);
INSERT INTO public.products VALUES ('722bd3d7-32a5-4b67-98c5-32b8a3b529b2', '2000000214771', 'TAM-21477', 'Greenfire Black Cream Haschisch 9g', 'The Artemis Greenfire Black Cream Hash offers a great smoking experience with a sweet, spicy scent and a unique creamy sticky consistency. With a high cannabinoid content of 31%, it fully convinces CBD lovers. Let yourself be gently and with a delicious scent floating into the orient of good hashish!', 50.00, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,measure:9g,path:hasch,brand:Artemis GmbH,material:Hemp,flavor:spicy', true, true, false, NULL, '21477', 'Artemis', NULL, '2026-06-30 15:48:07.72437+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=1c9746c2-192d-4a6c-b5a5-2692c39f85cf&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.928142+00', '2026-06-30 15:48:07.928144+00', NULL, NULL, NULL, 'cbd_open', 'CBD', 'cbd-18plus-default', true, '{"sort": "Indica / Sativa", "brand": "Artemis GmbH", "flavor": "spicy", "weight": "9 gr", "measure": "9g", "material": "hemp", "mounting": "Indoor", "cbd_content": "31 %", "thc_content": "0.95 %", "raw_material": "Hemp"}', '{"Sort": "Indica / Sativa", "Taste": "spicy", "Weight": "9 gr", "Material": "Hemp", "Mounting": "Indoor", "CBD content": "31 %", "THC content": "0.95 %", "Manufacturer": "Artemis GmbH", "Raw material": "Hemp"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '1c9746c2-192d-4a6c-b5a5-2692c39f85cf', 'https://www.artemisluzern.ch/en/product/greenfire-black-cream-haschisch-9g-21477', 'en', 'cbd/extrakte/hasch', false, NULL);
INSERT INTO public.products VALUES ('ad1c6174-f561-4bc6-94a6-dade6d769115', '2000000236476', 'TAM-23647', 'Monkey King "King Size Slim & Filter" Bubble Gum', 'Monkey King Papers – Aroma Edition: Fragrant papers with a real aroma effect The new Monkey King Papers with flavor variant really live up to their name: When you open the package, an intense, sweet scent immediately rises to your nose. No advertising ramblings – the aroma effect is immediately noticeable. The special highlight: After rubbing your buds, the typical weed smell often sticks to your fingers. With the Cookies Edition, you can easily cover this up. Rub your fingertips briefly on the packaging - and they take on the pleasant aroma scent of the papers. These papers not only offer high quality, but also a unique fragrance and user experience that clearly stands out from conventional papers. Perfect for those looking for that little bit extra.', 2.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/monkey-king,material:flax,size:kingsize,path:monkey-king,brand:Monkey King,flavor:Chewing gum', true, true, false, NULL, '23647', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=79fd2d6f-cf42-4c4e-951a-2fb835226bae&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.071088+00', '2026-06-30 15:10:50.07109+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Monkey King", "width": "4.4 cm", "flavor": "Chewing gum", "length": "10.8 cm", "material": "flax", "papierst_rke": "13 gr/m²", "raw_material": "Flax", "number_of_sheets_per_piece": "32 Stk."}', '{"Taste": "Chewing gum", "Width": "4.4 cm", "Length": "10.8 cm", "Manufacturer": "Monkey King", "Raw material": "Flax", "Papierstärke": "13 gr/m²", "Number of sheets per piece": "32 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '79fd2d6f-cf42-4c4e-951a-2fb835226bae', 'https://www.artemisluzern.ch/en/product/monkey-king-king-size-slim-filter-bubble-gum-23647', 'en', 'papers-co/drehpapier/monkey-king', false, NULL);
INSERT INTO public.products VALUES ('b742221b-f222-4b39-a49a-40b92379f201', '2000000056296', 'TAM-5629', 'OCB DW kurz schwarz', 'Thin... really thin! OCB Papers is one of the most popular and well-known brands of French papers. A real hit in the thin paper sector.', 2.00, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/ocb,brand:OCB,material:flax,path:ocb', true, true, false, NULL, '5629', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=4785365b-3424-4d61-bb88-bd439009d4ab&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.072813+00', '2026-06-30 15:10:50.072815+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "OCB", "width": "3.7 cm", "length": "6.7 cm", "material": "flax", "papierst_rke": "13 gr/m²", "raw_material": "Flax", "number_of_sheets_per_piece": "100 Stk."}', '{"Width": "3.7 cm", "Length": "6.7 cm", "Raw material": "Flax", "Papierstärke": "13 gr/m²", "Number of sheets per piece": "100 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '4785365b-3424-4d61-bb88-bd439009d4ab', 'https://www.artemisluzern.ch/en/product/ocb-dw-kurz-schwarz-5629', 'en', 'papers-co/drehpapier/ocb', false, NULL);
INSERT INTO public.products VALUES ('786f93f4-a41c-4741-a470-3686e188113e', '2000000089652', 'TAM-8965', 'Raw KS slim Artesano Classic brown mit Filter und Mischschale', '100% natural and unbleached. An absolutely good smoking experience! Each package contains the organic RAW papers. Each package is printed on eco paper using a Japanese thermography process. The RAW Artesano Paperpack with paper, filter and mixing tray is the ideal companion for on the go. Its cover serves as a windbreak when turning as well as a tobacco pad. These papers burn very slowly and thus ensure long and easy smoking pleasure.', 3.50, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/raw,brand:RAW,material:unbleached,size:kingsize,path:raw', true, true, false, NULL, '8965', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=4317bba0-7c8b-4a46-9f50-dd19cbbd9284&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.074513+00', '2026-06-30 15:10:50.074515+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "RAW", "width": "4 cm", "length": "10.9 cm", "material": "unbleached", "papierst_rke": "13 gr/m²", "raw_material": "Journey", "number_of_sheets_per_piece": "32 Stk."}', '{"Width": "4 cm", "Length": "10.9 cm", "Manufacturer": "RAW", "Raw material": "Journey", "Papierstärke": "13 gr/m²", "Number of sheets per piece": "32 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '4317bba0-7c8b-4a46-9f50-dd19cbbd9284', 'https://www.artemisluzern.ch/en/product/raw-ks-slim-artesano-classic-brown-mit-filter-und-mischschale-8965', 'en', 'papers-co/drehpapier/raw', false, NULL);
INSERT INTO public.products VALUES ('569420e3-2c17-4ab3-8e5e-a9de68e6f07c', '2000000212487', 'TAM-21248', 'Old School Papers', 'Expand your world of smoking pleasure with the Metal Eco Box with R36 Roll! In the beautiful world of smoking pleasure, there is a hidden treasure that you should definitely discover - the Metal Eco Box with R44 Roll. This stylish wooden box is more than just storage. It is a statement, an embodiment of your unique taste and awareness of nature. With a replacement paper roll and the Eco Metal Box R36, you don''t just get an item, but a lifestyle accessory that elevates smoking to a true art and you also contribute something to nature! The paper roll in this box is no ordinary paper. It is 100% natural and without additives. Each paper is perfectly proportioned to take your smoking pleasure to the next level. The roll container width of 4.6 cm not only offers space for the R36 roll, but also for your creativity and anticipation of unforgettable joints. The elegant design of this metal eco box emphasizes your uniqueness and attention to detail and nature. With the Metal Eco Box with R36 Wheel, you are not just carrying an object with you, but a piece of your personality.', 25.00, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/rips,material:hemp,path:rips,brand:OLD SCHOOL PAPERS', true, true, false, NULL, '21248', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=3c023edc-2121-4565-95ed-75707bfd32c5&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.076236+00', '2026-06-30 15:10:50.076237+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "OLD SCHOOL PAPERS", "width": "4.4 cm", "length": "5 m", "material": "hemp", "raw_material": "Hemp"}', '{"Width": "4.4 cm", "Length": "5 m", "Manufacturer": "OLD SCHOOL PAPERS", "Raw material": "Hemp"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '3c023edc-2121-4565-95ed-75707bfd32c5', 'https://www.artemisluzern.ch/en/product/old-school-papers-21248', 'en', 'papers-co/drehpapier/rips', false, NULL);
INSERT INTO public.products VALUES ('9c23d730-dd35-4d56-9da5-b66d6a887855', '2000000244044', 'TAM-24404', 'Purize King Size brown Slim', 'The Purize King Size Slim Papers "Brown" are the perfect companion for anyone looking for high-quality and tasteless rolling papers. Unbleached and made from natural wood fibres, they offer a clean smoking experience with the best burning behaviour. Thanks to the natural gum coating and a paper thickness of only 13 g/m², they are particularly thin and minimise any impairment of taste. Their slight transparency underlines the quality of the material. Technical details: Length: 10.8 cm Width: 4.4 cm Number of sheets per pack: 33 pcs. Raw material: Natural hemp Advantages at a glance: Optimal burning behavior without annoying additives Tasteless material for unadulterated enjoyment Sustainably produced quality for modern smokers', 1.50, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/smoking,brand:Smoking,material:hemp,material:unbleached,size:kingsize,path:smoking,brand:Purize', true, true, false, NULL, '24404', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=3c6fdf25-346b-4bf5-be5d-efc957e69654&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.081315+00', '2026-06-30 15:10:50.081317+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Smoking", "width": "4.4 cm", "length": "10.8 cm", "material": "hemp", "papierst_rke": "13 gr/m²", "raw_material": "Hemp", "number_of_sheets_per_piece": "42 Stk."}', '{"Width": "4.4 cm", "Length": "10.8 cm", "Manufacturer": "Purize", "Raw material": "Hemp", "Papierstärke": "13 gr/m²", "Number of sheets per piece": "42 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '3c6fdf25-346b-4bf5-be5d-efc957e69654', 'https://www.artemisluzern.ch/en/product/purize-king-size-brown-slim-24404', 'en', 'papers-co/drehpapier/smoking', false, NULL);
INSERT INTO public.products VALUES ('0c8a7b62-bd58-49ab-b4cf-d7d7f01a1728', '2000000259789', 'TAM-25978', 'G-Rollz Banksy’s Graffiti Set 2  Lightly Dyed Pink KS Papers mit Bröselschale', 'Banksy''s graffiti on your papers – stylish and environmentally conscious! With the G-Rollz | Banksy''s Graffiti Set 1 you get Banksy''s iconic street art on your paper and tips booklets. A practical extra: Each booklet contains a foldable tray - perfect for on the go! The sustainable G-Rollz products combine cool design with environmental awareness. Check the authenticity of each booklet by scanning the verification code. Dimensions of the papers: length 11 cm, width 4.4 cm. A must-have for every smart shooting session! This series surprises with two different subjects that are chosen at random – surprise guaranteed. Per booklet you get: 50 unbleached, chlorine- and non-GMO papers 50 vegan tips A bamboo stick for darning', 3.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier/ziggis,size:kingsize,path:ziggis,brand:G-Rollz', true, true, false, NULL, '25978', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=e303d2ed-bcf3-44b3-a79f-b384fa9969b2&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.083021+00', '2026-06-30 15:10:50.083022+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "G-Rollz", "width": "4.4 cm", "length": "10.8 cm", "raw_material": "Journey"}', '{"Width": "4.4 cm", "Length": "10.8 cm", "Manufacturer": "G-Rollz", "Raw material": "Journey"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'e303d2ed-bcf3-44b3-a79f-b384fa9969b2', 'https://www.artemisluzern.ch/en/product/g-rollz-banksys-graffiti-set-2-lightly-dyed-pink-ks-papers-mit-broeselschale-25978', 'en', 'papers-co/drehpapier/ziggis', true, NULL);
INSERT INTO public.products VALUES ('9a69b0c6-1054-4615-8356-3c5dd73b42f9', '2000000040547', 'TAM-4054', 'Gummihülle für Smoking King Size Hanfblatt grün', 'Gumi sleeve fits on all paper with king size format.', 5.90, NULL, 1, NULL, 'Rolling Papers', 'artemis:papers-co/drehpapier-dosen,brand:Smoking,material:hemp,size:kingsize,brand:Tamar', true, true, false, NULL, '4054', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=9bab87e4-00bc-46c8-a148-50d166b56127&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.084725+00', '2026-06-30 15:10:50.084726+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "kingsize", "brand": "Smoking", "material": "hemp"}', '{"Manufacturer": "Tamar"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '9bab87e4-00bc-46c8-a148-50d166b56127', 'https://www.artemisluzern.ch/en/product/gummihuelle-fuer-smoking-king-size-hanfblatt-gruen-4054', 'en', 'papers-co/drehpapier-dosen', true, NULL);
INSERT INTO public.products VALUES ('be782448-1e4a-4d0d-81c6-5b2bb9abdc16', '2000000258102', 'TAM-25810', 'Black Leaf Aufkleber für Glastips', 'Perfect fixation for glass filters Do you use glass filters in your joints and struggle with slipping or falling out? Black Leaf''s® food-grade adhesive strips are the ideal solution! Simply attach the paper directly to the glass filter - for optimal hold and relaxed smoking. The roll contains 50 sticky stickers that are perfectly pre-portioned. Thanks to the practical slot in the packaging, you can peel off the stickers individually - quickly and easily. The adhesive strips are suitable for glass filters with a diameter of 6 mm, 7 mm or 8 mm. A must-have for your smokeware collection! No slipping or falling out Easy to use and stylish', 4.90, NULL, 1, NULL, 'Filters & Tips', 'artemis:papers-co/filter/diverse,path:diverse,brand:Black Leaf', true, true, false, NULL, '25810', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=c0429c64-55a2-4b54-9274-5d8cce66b37c&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.086454+00', '2026-06-30 15:10:50.086456+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"brand": "Black Leaf"}', '{"Manufacturer": "Black Leaf"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'c0429c64-55a2-4b54-9274-5d8cce66b37c', 'https://www.artemisluzern.ch/en/product/black-leaf-aufkleber-fuer-glastips-25810', 'en', 'papers-co/filter/diverse', true, NULL);
INSERT INTO public.products VALUES ('720b4a79-fab0-41d8-8d6f-b39a789d723a', '2000000056609', 'TAM-5660', 'Aktivkohlefilter actiTube 8mm 100stk', 'Reduces the pollution of the respiratory tract every puff tastes pleasantly cool, gentle and dry No clogging No outflow of condensation Why activated carbon filters and still works: When smoking with Tune activated carbon filter, only a certain amount of active substances or pollutants adheres to the surface of the lungs with each puff, and residual smoke is always exhaled. Therefore, the composition of the inhaled smoke is extremely important. In the case of THC-containing smoke, activated carbon mainly filters the water-soluble substances from the smoke and thus changes the condensate/THC ratio in the direction of THC. With the Tune products, the pollutant content per THC is lower. The Tune activated carbon filter takes the damage out of the fabric. Tune recommends smoking slowly and in small puffs. Details: Diameter 8mm Length 35mm Box 100pcs.', 12.90, NULL, 1, NULL, 'Filters & Tips', 'artemis:papers-co/filter/kohlefilter,brand:Actitube,material:activated-carbon,size:8mm,measure:8mm,path:kohlefilter,brand:actiTube,color:White', true, true, false, NULL, '5660', 'Artemis', NULL, '2026-06-30 15:10:49.802339+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=93bba343-6688-4b37-ac3a-b6fe523a2e47&w=414&h=414&ext=.jpg', '2026-06-30 15:10:50.088141+00', '2026-06-30 15:10:50.088143+00', NULL, NULL, NULL, 'standard', 'Papers & Co', 'papers-co-smoking-accessory', true, '{"size": "8mm", "brand": "Actitube", "color": "White", "length": "3.5 cm", "measure": "8mm", "diameter": "8 mm", "material": "activated-carbon", "number_of_pieces_per_box": "100 Stk."}', '{"Color": "White", "Length": "3.5 cm", "Diameter": "8 mm", "Manufacturer": "actiTube", "Number of pieces per box": "100 Stk."}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '93bba343-6688-4b37-ac3a-b6fe523a2e47', 'https://www.artemisluzern.ch/en/product/aktivkohlefilter-actitube-8mm-100stk-5660', 'en', 'papers-co/filter/kohlefilter', false, NULL);
INSERT INTO public.products VALUES ('fa235d59-1ec8-488f-894e-1e97feae3ced', '2000000214788', 'TAM-21478', 'Greenfire Red Sputnik Haschisch 9g', 'The Artemis Red Sputnik is Swissmade and has a brown-dark red color. It convinces with gentle aromas and an earthy taste. With its high CBD content of around 32% and fine taste, this Sputnik will take you on a gentle journey into the indica galaxy!', 50.00, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,measure:9g,path:hasch,brand:Artemis GmbH,material:Hemp,flavor:earthy', true, true, false, NULL, '21478', 'Artemis', NULL, '2026-06-30 15:48:07.72437+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=204dd657-dfe7-4a58-9cbc-ea6dc3ad22b1&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.938785+00', '2026-06-30 15:48:07.938787+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"sort": "Indicates", "brand": "Artemis GmbH", "flavor": "earthy", "weight": "9 gr", "measure": "9g", "material": "hemp", "mounting": "Indoor", "cbd_content": "32 %", "thc_content": "0.75 %"}', '{"Sort": "Indicates", "Taste": "earthy", "Weight": "9 gr", "Material": "Hemp", "Mounting": "Indoor", "CBD content": "32 %", "THC content": "0.75 %", "Manufacturer": "Artemis GmbH"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '204dd657-dfe7-4a58-9cbc-ea6dc3ad22b1', 'https://www.artemisluzern.ch/en/product/greenfire-red-sputnik-haschisch-9g-21478', 'en', 'cbd/extrakte/hasch', false, NULL);
INSERT INTO public.products VALUES ('27ec6689-6e96-47cd-ba25-b9471b62db29', '2000000237268', 'TAM-23726', 'Hash Bunnies - La Plaquette x Hash Bunnies Christamas Special 5g', 'Limited Edition: Christmas Special with 52% CBD This exclusive limited edition combines the highest level of craftsmanship with winter enjoyment. The Christmas Special CBD hash is made up of top-notch Strawberry genetics and specially tuned terpenes that are perfect for the cold season. With an impressive 52% certified CBD, it''s the most concentrated product in our range – completely natural, with no additives or manipulations. The dark, oily and malleable consistency makes it a highlight for hashish lovers. When heated, an intense, woody cannabis aroma unfolds, while the taste convinces with fruity pollen strawberry accents - a winter experience full of depth and relaxation. A premium CBD resin from Switzerland that will enrich any collection and make the holidays unforgettable!', 24.90, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,measure:5g,path:hasch,brand:Hash Bunnies,material:Hemp', true, true, false, NULL, '23726', 'Artemis', NULL, '2026-06-30 15:48:07.72437+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=a0e7b633-98d6-4b61-815c-6752847161d2&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.946348+00', '2026-06-30 15:48:07.94635+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"brand": "Hash Bunnies", "weight": "5 gr", "measure": "5g", "material": "hemp", "cbd_content": "52 %", "thc_content": "0.8 %"}', '{"Weight": "5 gr", "Material": "Hemp", "CBD content": "52 %", "THC content": "0.8 %", "Manufacturer": "Hash Bunnies"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'a0e7b633-98d6-4b61-815c-6752847161d2', 'https://www.artemisluzern.ch/en/product/hash-bunnies-la-plaquette-x-hash-bunnies-christamas-special-5g-23726', 'en', 'cbd/extrakte/hasch', false, NULL);
INSERT INTO public.products VALUES ('53d28102-0237-4167-a813-624f86ef8c08', '2000000025056', 'TAM-2505', 'Glas-Kopf NS14 zylindrisch 25mm Ø 2er-Kopf', 'Original handmade glassware by our glassblower Plaisir Simply cut to length yourself with a glass cutter.', 22.00, NULL, 1, NULL, 'Bong Heads & Bowls', 'artemis:headshop/bong-pfeifenzubehoer/koepfe-schliff-14mm,material:glass,measure:25mm,path:koepfe-schliff-14mm,brand:Plaisir,material:Glass', true, true, false, NULL, '2505', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=66086abb-acd6-4b6b-b475-b988e3542bcc&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.987429+00', '2026-06-30 16:59:13.602196+00', NULL, NULL, NULL, 'standard', 'Headshop', 'headshop-smoking-paraphernalia', true, '{"brand": "Plaisir", "length": "24 cm", "measure": "25mm", "material": "glass", "kopfschliff": "14.4 mm", "outer_diameter": "2.5 cm"}', '{"Length": "24 cm", "Material": "Glass", "Kopfschliff": "14.4 mm", "Manufacturer": "Plaisir", "Outer diameter": "2.5 cm"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '66086abb-acd6-4b6b-b475-b988e3542bcc', 'https://www.artemisluzern.ch/en/product/glas-kopf-ns14-zylindrisch-25mm-o-2er-kopf-2505', 'en', 'headshop/bong-pfeifenzubehoer/koepfe-schliff-14mm', false, NULL);
INSERT INTO public.products VALUES ('11ee7eae-1e46-4fc8-b0a3-a879008e2961', '2000000211909', 'TAM-21190', 'VOZOL SWITCH 600 Kit violett Grape Ice', 'The Switch 600 kit comes with the Switch 600 device and matching a pod with the flavor. Depending on the color, you will get a different taste. The Switch 600 kit can be recharged and the pods are simply replaced after they are empty. The brand specializes in disposable vaping devices and has been gaining popularity in Europe for some time now. Vozol appliances impress above all with their quality, functionality and variety of tastes - no less than 17 different tastes are available for you to choose from. Apart from that, Vozol is the perfect start for smokers who want to switch to vaping.', 10.90, NULL, 1, NULL, 'Vape Pods', 'artemis:vape-co/prefilled/vozol,path:vozol,brand:Vozol,flavor:Grape', true, true, false, NULL, '21190', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=cc955b8e-5ac6-4981-a7ea-c86104b77714&w=414&h=414&ext=.jpg', '2026-06-30 15:48:08.012234+00', '2026-06-30 16:59:13.597416+00', NULL, NULL, NULL, 'standard', 'Vape & Co', 'vape-nicotine-context', true, '{"brand": "Vozol", "flavor": "Grape", "nicodemus": "20 mg"}', '{"Brand": "Vozol", "Taste": "Grape", "Nicodemus": "20 mg", "Manufacturer": "Vozol"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'cc955b8e-5ac6-4981-a7ea-c86104b77714', 'https://www.artemisluzern.ch/en/product/vozol-switch-600-kit-violett-grape-ice-21190', 'en', 'vape-co/prefilled/vozol', false, NULL);
