INSERT INTO public.products VALUES ('0a05e18a-95b6-4592-b62a-b6b1e434c5f3', '2000000205335', 'TAM-20533', 'Hash Gang Bubble Hasch 4.20gr.', 'Bubble Hash is the first hash from the Supreme Swiss Hash Series, the premium hash line of the Hash Gang! It has the color and properties of a classic bubble hashish and throws the familiar little bubbles when you heat it slightly with a lighter. Its smell is particularly pronounced and its intense flavor is reminiscent of the best well-known hashish, but without the high effect. With its high concentration of CBD, it''s perfect for relaxing at the end of the day. A great success of our favorite Swiss producer - the Hash Gang!', 38.00, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,path:hasch,brand:Hash Gang,material:Hemp', true, true, false, NULL, '20533', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=30b85f38-a8cc-4ed1-9417-9e0efde80df4&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.982112+00', '2026-06-30 16:59:13.594448+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"brand": "Hash Gang", "weight": "4.2 gr", "material": "hemp", "cbd_content": "50 %", "thc_content": "0.8 %"}', '{"Weight": "4.2 gr", "Material": "Hemp", "CBD content": "50 %", "THC content": "0.8 %", "Manufacturer": "Hash Gang"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '30b85f38-a8cc-4ed1-9417-9e0efde80df4', 'https://www.artemisluzern.ch/en/product/hash-gang-bubble-hasch-420gr-20533', 'en', 'cbd/extrakte/hasch', false, NULL);
