INSERT INTO public.products VALUES ('0fec64fb-4fb6-45b6-b5a4-300488670460', '2000000205007', 'TAM-20500', 'Hash Gang Manali Cream 4.20gr.', 'Like Charras, Manali Cream has been known for decades as one of the best hashish strains in the world. Its soft, creamy consistency and intense smell will delight all Black Afghan fans. The extremely high concentration of CBD will instantly relax you and throw you into chill mode. Closer to the original is not possible - an experience that is second to none!', 29.00, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,path:hasch,brand:S&B Solution,material:Hemp', true, true, false, NULL, '20500', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=dead6512-a961-4bc4-b97c-7fe432d6fca3&w=414&h=414&ext=.jpg', '2026-06-30 15:48:08.003451+00', '2026-06-30 16:59:13.597413+00', NULL, NULL, NULL, 'cbd_open', 'CBD', 'cbd-18plus-default', true, '{"brand": "S&B Solution", "weight": "4.2 gr", "material": "hemp", "cbd_content": "45 %", "thc_content": "0.8 %"}', '{"Weight": "4.2 gr", "Material": "Hemp", "CBD content": "45 %", "THC content": "0.8 %", "Manufacturer": "S&B Solution"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'dead6512-a961-4bc4-b97c-7fe432d6fca3', 'https://www.artemisluzern.ch/en/product/hash-gang-manali-cream-420gr-20500', 'en', 'cbd/extrakte/hasch', false, NULL);
INSERT INTO public.products VALUES ('12bdca5e-2d42-424a-8529-f1320e61f8d0', '2000000230122', 'TAM-23012', 'Lama Weed Trichoselect D Sweet Dreams 5g', 'Trichoselect D – Sweet Dreams (5g) by Lamaweed Swiss hash indulgence for relaxing nights Experience a classic hash pleasure as it should be with Trichoselect D – Sweet Dreams by Lamaweed: Dark, soft, aromatic. Made in Switzerland, in harmony with nature, this CBD hash convinces with its pleasant consistency and excellent processing quality - without any tobacco or synthetic additives. The slightly soft structure makes it particularly easy to use - whether rolled, in a vaporizer or in a pipe. The aroma is earthy-spicy with gentle notes that perfectly match the relaxed effect. With less than 1% THC, Sweet Dreams remains perfectly legal and is ideal for enjoying in the evening. Produced in Switzerland: quality from controlled cultivation Dark brown color & soft consistency: easy to mold and versatile Free of tobacco & additives: natural product 5 g pack: high-quality hash at a fair price', 30.00, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,measure:5g,path:hasch,brand:Lama Weed,material:Hemp', true, true, false, NULL, '23012', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=0394cbfd-4e33-4888-aacf-5a4e697bb03e&w=414&h=414&ext=.jpg', '2026-06-30 15:48:08.017492+00', '2026-06-30 16:59:13.597417+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"brand": "Lama Weed", "weight": "5 gr", "measure": "5g", "material": "hemp"}', '{"Weight": "5 gr", "Material": "Hemp", "Manufacturer": "Lama Weed"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '0394cbfd-4e33-4888-aacf-5a4e697bb03e', 'https://www.artemisluzern.ch/en/product/lama-weed-trichoselect-d-sweet-dreams-5g-23012', 'en', 'cbd/extrakte/hasch', false, NULL