INSERT INTO public.products VALUES ('1dc1f3f8-88f7-4e0a-843d-f2addd4a1f06', '2000000220116', 'TAM-22011', 'VOZOL Gear S 4000 KIT Space Grey / Strawberry Ice Cream', 'The well-known device manufacturer Vozol has made a precision landing with the kit of the Gear S 4000. The easiest way to vape is the disposable e-cigarette. The Vozol Gear S 4000 scores with a chic and compact body, which can be taken anywhere thanks to the carabiner. Due to its small size, the Gear S 4000 can also be taken into your pocket or handbag. Since the body of the Vozol is made of 65% PCR material and anodized aluminum, this disposable vape is very robust. In addition, a removable silicone cap ensures that no dirt or dust gets into your mouthpiece. As we all know, looks are not everything, which is why the Vozol Gear S 4000 also convinces with a VAMT mesh coil inside. This coil and the advanced technology of the high-quality airflow design make the Gear S 4000 very pleasant to vape. This makes the taste more aromatic and natural. According to the manufacturer, about 4000* trains are to be expected. (*without guarantee) The 500mAh battery ensures super fast charging, so your disposable cigarette can be used again right away. The disposable vape is filled with 20MG/ML nicotine salt and aromatic liquid. The Vozol Gear S 4000 is available from us in different flavors. So everyone gets their preferred flavor. The Vozol Gear S 4000 is a powerful and reliable disposable vape. This makes it suitable for anyone who wants an intense and long-lasting vaping experience. The Gear S 4000 is a disposable product and cannot be refilled. If the e-cigarette is empty, recycle the empty vape properly. You can return empty e-cigarettes to any point of sale or directly to us.', 15.90, NULL, 1, NULL, 'Vape Pods', 'artemis:vape-co/prefilled/vozol,path:vozol,brand:Vozol,flavor:Mango', true, true, false, NULL, '22011', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=520744a4-940c-40d9-a510-f7115b7b80c5&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.940755+00', '2026-06-30 16:59:13.601077+00', NULL, NULL, NULL, 'standard', 'Vape & Co', 'vape-nicotine-context', true, '{"brand": "Vozol", "flavor": "Mango", "nicodemus": "20 mg"}', '{"Taste": "Mango", "Nicodemus": "20 mg", "Manufacturer": "Vozol"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '520744a4-940c-40d9-a510-f7115b7b80c5', 'https://www.artemisluzern.ch/en/product/vozol-gear-s-4000-kit-space-grey-strawberry-ice-cream-22011', 'en', 'vape-co/prefilled/vozol', false, NULL);
