INSERT INTO public.products VALUES ('208ac87c-fd61-4573-97f5-90f546f1ad85', '2000000229713', 'TAM-22971', 'Hash Bunnies - Premium Swiss CBD Hash - Bubble Hash - 7g', 'Versatile and smooth, it''s the ideal introduction to the world of CBD hashish. With the Hash Bunnies - Bubble Hash you get an absolute highlight: premium hash, which is obtained exclusively by ice water extraction - without any solvents. This process guarantees maximum purity, the highest density of active ingredients and a uniquely natural aroma.', 49.90, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,measure:7g,path:hasch,brand:Hash Bunnies,material:Hemp', true, true, false, NULL, '22971', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=22d4dc75-f616-4daf-8a99-da52b1f5b272&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.960714+00', '2026-06-30 16:59:13.601078+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"brand": "Hash Bunnies", "weight": "7 gr", "measure": "7g", "material": "hemp", "cbd_content": "24 %", "thc_content": "0.8 %"}', '{"Weight": "7 gr", "Material": "Hemp", "CBD content": "24 %", "THC content": "0.8 %", "Manufacturer": "Hash Bunnies"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '22d4dc75-f616-4daf-8a99-da52b1f5b272', 'https://www.artemisluzern.ch/en/product/hash-bunnies-premium-swiss-cbd-hash-bubble-hash-7g-22971', 'en', 'cbd/extrakte/hasch', false, NULL);
