INSERT INTO public.products VALUES ('39165d55-b2d5-4c37-a577-3a3614e09650', '2000000232676', 'TAM-23267', 'Tresor AXE Deo Gold Temptation', 'AXE Stash Safe - Your personal secret hiding place in deodorant format! You probably know AXE as a brand for refreshing deodorants. But now there is the AXE Stash Safe, a clever and inconspicuous stash in deodorant format. Why the AXE Stash Safe? Imagine being able to store your valuables in a place no one would ever suspect - in your deodorant! The AXE Stash Safe looks like an ordinary deodorant, but inside it hides a secret compartment that measures 8 cm high and 3.5 cm in diameter. That''s enough to keep your little treasures safe. Whether you have cash, jewelry, important documents, or other valuable items you want to protect, the AXE Cache Safe has you covered. No one would ever think of looking for valuables in your deodorant.', 39.00, NULL, 1, NULL, 'Storage & Safes', 'artemis:headshop/verstecktresore', true, false, false, NULL, '23267', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=246b227c-9a6a-4807-8bb1-bfd0f60093b2&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.999835+00', '2026-06-30 16:59:13.601824+00', NULL, NULL, NULL, 'standard', 'Headshop', 'storage-lifestyle-not-age-restricted (DRAFT, pending Treuhänder)', true, 'null', 'null', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '246b227c-9a6a-4807-8bb1-bfd0f60093b2', 'https://www.artemisluzern.ch/en/product/tresor-axe-deo-gold-temptation-23267', 'en', 'headshop/verstecktresore', false, NULL);
