INSERT INTO public.products VALUES ('53188f6f-b602-4f95-bcfb-6b58cbd4db03', '2000000214436', 'TAM-21443', 'VOZOL Gear S 4000 KIT Space Gray / Blue Razz Ice', 'The well-known device manufacturer Vozol has made a precision landing with the kit of the Gear S 4000. The easiest way to vape is the disposable e-cigarette. The Vozol Gear S 4000 scores with a chic and compact body, which can be taken anywhere thanks to the carabiner. Due to its small size, the Gear S 4000 can also be taken into your pocket or handbag. Since the body of the Vozol is made of 65% PCR material and anodized aluminum, this disposable vape is very robust. In addition, a removable silicone cap ensures that no dirt or dust gets into your mouthpiece. As we all know, looks are not everything, which is why the Vozol Gear S 4000 also convinces with a VAMT mesh coil inside. This coil and the advanced technology of the high-quality airflow design make the Gear S 4000 very pleasant to vape. This makes the taste more aromatic and natural. According to the manufacturer, about 4000* trains are to be expected. (*without guarantee) The 500mAh battery ensures super fast charging, so your disposable cigarette can be used again right away. The disposable vape is filled with 20MG/ML nicotine salt and aromatic liquid. The Vozol Gear S 4000 is available from us in different flavors. So everyone gets their preferred flavor. The Vozol Gear S 4000 is a powerful and reliable disposable vape. This makes it suitable for anyone who wants an intense and long-lasting vaping experience. The Gear S 4000 is a disposable product and cannot be refilled. If the e-cigarette is empty, recycle the empty vape properly. You can return empty e-cigarettes to any point of sale or directly to us.', 15.90, NULL, 1, NULL, 'Vape Pods', 'artemis:vape-co/prefilled/vozol,path:vozol,brand:Vozol,flavor:Mango', true, true, false, NULL, '21443', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=d1eaa401-e14c-4187-8799-f7d833cf5067&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.931337+00', '2026-06-30 16:59:13.602195+00', NULL, NULL, NULL, 'standard', 'Vape & Co', 'vape-nicotine-context', true, '{"brand": "Vozol", "flavor": "Mango", "nicodemus": "20 mg"}', '{"Taste": "Mango", "Nicodemus": "20 mg", "Manufacturer": "Vozol"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'd1eaa401-e14c-4187-8799-f7d833cf5067', 'https://www.artemisluzern.ch/en/product/vozol-gear-s-4000-kit-space-gray-blue-razz-ice-21443', 'en', 'vape-co/prefilled/vozol', false, NULL);
INSERT INTO public.products VALUES ('55ac5634-5e00-4791-8626-9e03798d75ed', '2000000193731', 'TAM-19373', 'STALIN PhoneBag Textil Big camouflage 170x110mm', 'Stalin Big is slightly larger than the normal Stalin and therefore larger smartphones such as the Galaxy S3 now fit easily into this tap-proof mobile phone case. The Stalin is handmade from black imitation leather and each individual mobile phone case is subjected to a functional test. With an inner pocket size of approx. 170 x 100mm, the Stalin is suitable for all common mobile phones and smartphones. With its triple sheathing, the Stalin also offers 3x as much protection as conventional spy-proof mobile phone cases. The Stalin mobile phone cases are practical and tap-proof storage bags for smartphones as well as for older mobile phone models. Wherever you are and have your mobile phone in this pocket, they cannot track your location and harass you under any circumstances. These Stalin bags are the products of the future! Stalin is currently the safest and best product on the market! Stalin Big is slightly larger than the normal Stalin and therefore larger smartphones such as the Galaxy S3 now fit easily into this tap-proof mobile phone case. The Stalin is handmade from black imitation leather and each individual mobile phone case is subjected to a functional test. With an inner pocket size of approx. 170 x 100mm, the Stalin is suitable for all common mobile phones and smartphones. With its triple sheathing, the Stalin also offers 3x as much protection as conventional spy-proof mobile phone cases.', 129.00, NULL, 1, NULL, 'Storage & Safes', 'artemis:headshop/verstecktresore,brand:Tamar,color:Camouflage', true, false, false, NULL, '19373', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=7e4e54ae-3a66-41c0-bb7c-83b91e93737f&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.985691+00', '2026-06-30 16:59:13.602578+00', NULL, NULL, NULL,