INSERT INTO public.products VALUES ('751dada1-8ca2-40f8-a3d1-1ba475249fdd', '2000000212562', 'TAM-21256', 'Tresor Autoschlüssel', 'Deceptively real car key safe – your secret valuables hiding place! Imagine being able to store your small valuables in a place that no one would ever suspect. The car key safe is the perfect solution to keep your secrets safe without anyone raising suspicions. This key safe is not only a safe place to store it, but also a true masterpiece of camouflage. From the outside, it looks exactly like a normal car key. No one will ever suspect that there is anything valuable hidden in it. With dimensions of just 30x50x10mm, this safe is small and handy. You can easily carry it in your pocket or store it in a safe place. Whether at home, in the office or on the road, this key safe is always ready for use. Operation is child''s play. You can open the safe by pulling the key apart and removing the rear lid. Inside, you''ll find a small space for small valuables like jewelry, one or two banknotes, or important notes. The camouflage of this safe is so convincing that even a professional thief would never suspect that valuables are hidden here. This makes it the ideal choice for keeping your secrets and valuables safe. Protect your valuables from prying eyes and unwanted access with this ingenious car key safe.', 29.00, NULL, 1, NULL, 'Storage & Safes', 'artemis:headshop/verstecktresore', true, false, false, NULL, '21256', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=a43cd235-26e4-4f75-9898-132ad4ec1b5b&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.992785+00', '2026-06-30 16:59:13.603341+00', NULL, NULL, NULL, 'standard', 'Headshop', 'storage-lifestyle-not-age-restricted (DRAFT, pending Treuhänder)', true, 'null', 'null', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'a43cd235-26e4-4f75-9898-132ad4ec1b5b', 'https://www.artemisluzern.ch/en/product/tresor-autoschluessel-21256', 'en', 'headshop/verstecktresore', true, NULL);
INSERT INTO public.products VALUES ('75d6412f-939c-4746-b822-5ad9826f6355', '2000000214382', 'TAM-21438', 'VOZOL Gear S 6000 Pod Strawberry Ice Cream', 'Immerse yourself in a world full of flavors with the new Vozol Gear S Pods. Each pod is carefully filled with premium e-liquids that provide maximum flavor and satisfaction. The pods are at the heart of your vaping experience, designed to provide you with pure and intense flavors with every inhalation. As we all know, looks are not everything, which is why the Vozol Gear S also convinces with a VAMT mesh coil inside. This coil and the advanced technology of the high-quality airflow design make the Gear S very comfortable to vape. This makes the taste more aromatic and natural.', 19.90, NULL, 1, NULL, 'Vape Pods', 'artemis:vape-co/prefilled/vozol,path:vozol,brand:Vozol,flavor:Mango', true, true, false, NULL, '21438', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=906aab61-5163-4060-bd35-150856b2254b&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.95532+00', '2026-06-30 16:59:13.603934+00', NULL, NULL, NULL, 'standard', 'Vape & Co', 'vape-nicotine-context', true, '{"brand": "Vozol", "flavor": "Mango", "nicodemus": "20 mg"}', '{"Taste": "Mango", "Nicodemus": "20 mg", "Manufacturer": "Vozol"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '906aab61-5163-4060-bd35-150856b2254b', 'https://www.artemisluzern.ch/en/product/vozol-gear-s-6000-pod-strawberry-ice-cream-21438', 'en', 'vape-co/prefilled/vozol', false, NULL);
