INSERT INTO public.products VALUES ('86349b40-880d-42ed-855f-4a8b098bbe3a', '2000000204994', 'TAM-20499', 'Hash Gang Double Zero 4.20gr.', 'Double Zero is a hashish of the highest quality that comes from the first pass of the screening process. This gives it a very balanced taste and allows for a high CBD content. The Double Zero breaks down easily when heated with a lighter, so it''s easy to add to your mix.', 25.00, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,path:hasch,brand:S&B Solution,material:Hemp', true, true, false, NULL, '20499', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=0f9c6b10-e287-4904-aa7a-4c1ff63eb421&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.989188+00', '2026-06-30 16:59:13.603937+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"brand": "S&B Solution", "weight": "4.2 gr", "material": "hemp", "cbd_content": "40 %", "thc_content": "0.8 %"}', '{"Weight": "4.2 gr", "Material": "Hemp", "CBD content": "40 %", "THC content": "0.8 %", "Manufacturer": "S&B Solution"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '0f9c6b10-e287-4904-aa7a-4c1ff63eb421', 'https://www.artemisluzern.ch/en/product/hash-gang-double-zero-420gr-20499', 'en', 'cbd/extrakte/hasch', false, NULL);
INSERT INTO public.products VALUES ('86aa8539-026c-4ce3-a822-8c7ba1775d1a', '2000000211916', 'TAM-21191', 'VOZOL SWITCH 600 Kit rot Pink Lemonade', 'The Switch 600 kit comes with the Switch 600 device and matching a pod with the flavor. Depending on the color, you will get a different taste. The Switch 600 kit can be recharged and the pods are simply replaced after they are empty. The brand specializes in disposable vaping devices and has been gaining popularity in Europe for some time now. Vozol appliances impress above all with their quality, functionality and variety of tastes - no less than 17 different tastes are available for you to choose from. Apart from that, Vozol is the perfect start for smokers who want to switch to vaping.', 10.90, NULL, 1, NULL, 'Vape Pods', 'artemis:vape-co/prefilled/vozol,path:vozol,brand:Vozol,flavor:Grapefruit', true, true, false, NULL, '21191', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=f55e8f82-b28f-4d01-8379-a15158be1245&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.990972+00', '2026-06-30 16:59:13.603938+00', NULL, NULL, NULL, 'standard', 'Vape & Co', 'vape-nicotine-context', true, '{"brand": "Vozol", "flavor": "Grapefruit", "nicodemus": "20 mg"}', '{"Brand": "Vozol", "Taste": "Grapefruit", "Nicodemus": "20 mg", "Manufacturer": "Vozol"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'f55e8f82-b28f-4d01-8379-a15158be1245', 'https://www.artemisluzern.ch/en/product/vozol-switch-600-kit-rot-pink-lemonade-21191', 'en', 'vape-co/prefilled/vozol', false, NULL);
