INSERT INTO public.products VALUES ('889df711-dbd6-447b-874d-2449ea66d616', '2000000229690', 'TAM-22969', 'Hash Bunnies - Premium Swiss CBD Hash - 4x Filtre - 7g', 'With the Hash Bunnies - Golden Piatella, we present you the absolute flagship of the art of hashing: A creamy, almost melting CBD hash produced by the elaborate Piatella Cure technique - inspired by traditional Temple Ball craftsmanship and state-of-the-art Swiss innovation and precision. This golden hash is not pressed, but matured - slowly, controlled, with perfect moisture. The result: an incredibly aromatic, buttery masterpiece for true connoisseurs.', 49.90, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,measure:7g,path:hasch,brand:Hash Bunnies,material:Hemp', true, true, false, NULL, '22969', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=bf7a53ef-9021-4959-902e-3b714b924a9d&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.953593+00', '2026-06-30 16:59:13.606081+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"brand": "Hash Bunnies", "weight": "7 gr", "measure": "7g", "material": "hemp", "cbd_content": "47 %", "thc_content": "0.8 %"}', '{"Weight": "7 gr", "Material": "Hemp", "CBD content": "47 %", "THC content": "0.8 %", "Manufacturer": "Hash Bunnies"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', 'bf7a53ef-9021-4959-902e-3b714b924a9d', 'https://www.artemisluzern.ch/en/product/hash-bunnies-premium-swiss-cbd-hash-4x-filtre-7g-22969', 'en', 'cbd/extrakte/hasch', false, NULL);
INSERT INTO public.products VALUES ('8d0f6021-7152-4683-a605-af9f57fd9382', '2000000205328', 'TAM-20532', 'Hash Gang Temple Ball 4.20gr.', 'The Temple Ball is one of the best CBD hashish currently available and belongs to the SUPREME line of the Hash Gang. As the name suggests, it has the shape of a classic black temple ball, according to the original, handcrafted by our experts. You can easily roll it into a "worm" that you can place in the center of your joint. It smells wonderfully authentic when it is slightly heated and tastes so similar to the original that there is a risk of confusion. A real success of our favorite Swiss producer!', 42.00, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,path:hasch,brand:Hash Gang,material:Hemp', true, true, false, NULL, '20532', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=3412a71c-4d06-493f-b660-de15ab7a1568&w=414&h=414&ext=.jpg', '2026-06-30 15:48:08.010461+00', '2026-06-30 16:59:13.606084+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"brand": "Hash Gang", "weight": "4.2 gr", "material": "hemp", "cbd_content": "50 %", "thc_content": "0.8 %"}', '{"Weight": "4.2 gr", "Material": "Hemp", "CBD content": "50 %", "THC content": "0.8 %", "Manufacturer": "Hash Gang"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '3412a71c-4d06-493f-b660-de15ab7a1568', 'https://www.artemisluzern.ch/en/product/hash-gang-temple-ball-420gr-20532', 'en', 'cbd/extrakte/hasch', false, NULL);
INSERT INTO public.products VALUES ('8d576c9e-1516-48f9-8e0f-f739909a3f1a', '2000000129402', 'TAM-12940', 'Glas-Kopf NS14 rund 30mm Ø Eject a Bowl grün gestreift', 'Beautiful, functional glass head with kick function! When you press on the glass head, the smoked material is ejected. If the head is only slightly pressed while smoking, the draught increases...... KICK! Fits all adapters with NS14 grinding.', 19.00, NULL, 1, NULL, 'Bong Heads & Bowls', 'artemis:headshop/bong-pfeifenzubehoer/koepfe-schliff-14mm,material:glass,measure:30mm,path:koepfe-schliff-14mm,color:Green,material:Glass', true, true, false, NULL, '12940', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=3b939c43-6697-436e-8847-e827181880a2&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.958938+00', '2026-06-30 16:59:13.606085+00', NULL, NULL, NULL, 'standard', 'Headshop', 'headshop-smoking-paraphernalia', true, '{"color": "Green", "height": "2 cm", "measure": "30mm", "material": "glass", "kopfschliff": "14.4 mm", "outer_diameter": "3 cm", "diameter_inside": "1.5 cm"}', '{"Color": "Green", "Height": "2 cm", "Material": "Glass", "Kopfschliff": "14.4 mm", "Outer diameter": "3 cm", "Diameter inside": "1.5 cm"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', '["needs_translation"]', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '3b939c43-6697-436e-8847-e827181880a2', 'https://www.artemisluzern.ch/en/product/glas-kopf-ns14-rund-30mm-o-eject-a-bowl-gruen-gestreift-12940', 'en', 'headshop/bong-pfeifenzubehoer/koepfe-schliff-14mm', true, NULL);
