INSERT INTO public.products VALUES ('c691a9fd-0c20-4c7a-8192-c13a0b158150', '2000000229706', 'TAM-22970', 'Hash Bunnies - Premium Swiss CBD Hash - Frozen Dry - 7g', 'Dive into the next level of CBD enjoyment with the Hash Bunnies - Frozen Dry. Through state-of-the-art freeze-drying, the raw material for this hash is processed particularly gently in order to preserve terpenes, cannabinoids and aromas in their purest form. The result: an ultra-pure, fluffy, blueberry-scented CBD hash experience that delivers depth, character, and impact.', 49.90, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,measure:7g,path:hasch,brand:Hash Bunnies,material:Hemp', true, true, false, NULL, '22970', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=5b11d899-8f4a-4ed0-9cae-cd450834cd5b&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.967816+00', '2026-06-30 16:59:13.609505+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"brand": "Hash Bunnies", "weight": "7 gr", "measure": "7g", "material": "hemp", "cbd_content": "24 %", "thc_content": "0.8 %"}', '{"Weight": "7 gr", "Material": "Hemp", "CBD content": "24 %", "THC content": "0.8 %", "Manufacturer": "Hash Bunnies"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '5b11d899-8f4a-4ed0-9cae-cd450834cd5b', 'https://www.artemisluzern.ch/en/product/hash-bunnies-premium-swiss-cbd-hash-frozen-dry-7g-22970', 'en', 'cbd/extrakte/hasch', false, NULL);
INSERT INTO public.products VALUES ('cac33eaa-3408-4c1b-bb35-d46f623a18b2', '2000000205021', 'TAM-20502', 'Hash Gang Jamaican Pollen 4.20gr.', 'Jamaican Pollen is an exquisite pollen, intense and fruity-sweet in taste and resinous. Pure Caribbean! It is soft and pleasant to work with and, with its high CBD content, it is just the right product to give your hashish joint the decisive kick.', 20.00, NULL, 1, NULL, 'CBD Hash', 'artemis:cbd/extrakte/hasch,material:hemp,path:hasch,brand:S&B Solution,material:Hemp', true, true, false, NULL, '20502', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=2712f2f6-405e-4762-a96e-2c4520c502c5&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.996287+00', '2026-06-30 16:59:13.609505+00', NULL, NULL, NULL, 'cbd_hemp', 'CBD', 'class:cbd_hemp', true, '{"brand": "S&B Solution", "weight": "4.2 gr", "material": "hemp", "cbd_content": "35 %", "thc_content": "0.8 %"}', '{"Weight": "4.2 gr", "Material": "Hemp", "CBD content": "35 %", "THC content": "0.8 %", "Manufacturer": "S&B Solution"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '2712f2f6-405e-4762-a96e-2c4520c502c5', 'https://www.artemisluzern.ch/en/product/hash-gang-jamaican-pollen-420gr-20502', 'en', 'cbd/extrakte/hasch', false, NULL);
