INSERT INTO public.products VALUES ('f345d543-22c9-4727-baa1-51b21122c9d1', '2000000230801', 'TAM-23080', 'c Safes Safe-Box 5XL mit Magnet 255x330x130mm', 'The ''Secret Safes'' Safe Box with Magnet is made of high-resistance ABS plastic with stainless steel pivot bolts and is lined with foam on the inside to protect valuables. This ''Secret Safe'' can be securely attached under the trolley when travelling due to the magnets and is waterproof and airtight thanks to the O-rubber seal, so your valuables are safe from rain and mud. But it can also be inconspicuously fixed at home behind household appliances and many other metallic objects and is thus protected from thieves or prying eyes. Made in the USA.', 139.00, NULL, 1, NULL, 'Storage & Safes', 'artemis:headshop/verstecktresore,brand:Tamar', true, false, false, NULL, '23080', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=3e3e5ee5-2958-4155-b37b-f4e3130effc3&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.934389+00', '2026-06-30 16:59:13.610499+00', NULL, NULL, NULL, 'standard', 'Headshop', 'storage-lifestyle-not-age-restricted (DRAFT, pending Treuhänder)', true, '{"brand": "Tamar"}', '{"Manufacturer": "Tamar"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '3e3e5ee5-2958-4155-b37b-f4e3130effc3', 'https://www.artemisluzern.ch/en/product/c-safes-safe-box-5xl-mit-magnet-255x330x130mm-23080', 'en', 'headshop/verstecktresore', false, NULL);
INSERT INTO public.products VALUES ('f7cdbf74-2bf4-479e-848a-f5653b7ae845', '2000000193748', 'TAM-19374', 'STALIN PhoneBag Kunstleder Big schwarz  Carbon Look 215x145mm', 'The STALIN PhoneBag – for espionage-proof privacy! Product details: Big+ faux leather – carbon look with dark grey stitching The undisputed bestseller among shielding mobile phone cases is handmade in Germany. All bags are made of high-quality materials and are subjected to a functional test before delivery. The STALIN, an indispensable gadget for you and your data. Scientifically tested and certified, this quality product ensures that maximum protection against espionage is achieved. All connections and signals - GPRS, WLAN, Bluetooth, RFID, NFR, etc. - are blocked neither your location can be located nor your conversations tapped Close-up scans or capturing mobile devices through area scans are impossible KeylessGo car thefts are unsuccessful High-frequency electromagnetic radiation and low-frequency alternating electric fields are shielded Please note: In order for all these protective measures to work properly, the bag must be closed! In the end, the latest and state-of-the-art technology ensures that the STALIN mobile phone cases protect your privacy in the best possible way. The structure and materials have been specially developed for this purpose. The inner lining consists of a multi-layer fleece that contains multi-layered shielding fiber panels. An enormously dense and highly metallized polyamide fabric forms the basis for this special nonwoven. In addition, the closures are triple magnetic locking systems and are mounted on the inside. As a result, they provide reliable protection and can withstand even heavy use. And the cover of the STALIN - optionally made of real or artificial leather - rounds off your safety zone completely. The result: When closed, all contact with the outside world is blocked and signals are made unrecognizable.', 159.00, NULL, 1, NULL, 'Storage & Safes', 'artemis:headshop/verstecktresore,brand:Tamar,color:Black,material:Imitation leather', true, false, false, NULL, '19374', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=95296d8b-25ca-441f-a824-45318a52c727&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.978398+00', '2026-06-30 16:59:13.610499+00', NULL, NULL, NULL, 'standard', 'Headshop', 'storage-lifestyle-not-age-restricted (DRAFT, pending Treuhänder)', true, '{"brand": "Tamar", "color": "Black", "width": "14.5 cm", "length": "21.5 cm", "material": "Imitation leather"}', '{"Color": "Black", "Width": "14.5 cm", "Length": "21.5 cm", "Material": "Imitation leather", "Manufacturer": "Tamar"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '95296d8b-25ca-441f-a824-45318a52c727', 'https://www.artemisluzern.ch/en/product/stalin-phonebag-kunstleder-big-schwarz-carbon-look-215x145mm-19374', 'en', 'headshop/verstecktresore', false, NULL);
INSERT INTO public.products VALUES ('fb3d3d49-3254-4882-abaf-bbd963c2ae9b', '2000000220178', 'TAM-22017', 'VOZOL Gear S 4000 Pod Strawberry Ice Cream', 'Immerse yourself in a world full of flavors with the new Vozol Gear S Pods. Each pod is carefully filled with premium e-liquids that provide maximum flavor and satisfaction. The pods are at the heart of your vaping experience, designed to provide you with pure and intense flavors with every inhalation. As we all know, looks are not everything, which is why the Vozol Gear S also convinces with a VAMT mesh coil inside. This coil and the advanced technology of the high-quality airflow design make the Gear S very comfortable to vape. This makes the taste more aromatic and natural.', 12.90, NULL, 1, NULL, 'Vape Pods', 'artemis:vape-co/prefilled/vozol,path:vozol,brand:Vozol,flavor:Mango', true, true, false, NULL, '22017', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=59c5bc7a-28c7-4585-89a6-5059978959a6&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.948122+00', '2026-06-30 16:59:13.611563+00', NULL, NULL, NULL, 'standard', 'Vape & Co', 'vape-nicotine-context', true, '{"brand": "Vozol", "flavor": "Mango", "nicodemus": "20 mg"}', '{"Taste": "Mango", "Nicodemus": "20 mg", "Manufacturer": "Vozol"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '59c5bc7a-28c7-4585-89a6-5059978959a6', 'https://www.artemisluzern.ch/en/product/vozol-gear-s-4000-pod-strawberry-ice-cream-22017', 'en', 'vape-co/prefilled/vozol', false, NULL);
INSERT INTO public.products VALUES ('ff2d4afd-b63e-4f32-809d-2ce2be49d98a', '2000000240107', 'TAM-24010', 'Metall-Dose mit Halsband "Pillendose" 60mm', 'Discretion meets style and functionality The portable Pill Case Bullet is the ideal accessory for on the go when you want to store small items safely and inconspicuously. Thanks to its unique cartridge design and high-quality aluminum manufacturing, it combines style with durability. Choose between the trendy colours black, silver or gold for an individual look. Practical details for your everyday life The screw-on cap allows for quick access, while the sturdy closure securely protects your belongings. Whether keys, pills or other small items - this hiding place is a must-have for all those who value discretion. Perfectly tailored to modern headshop customers! Dimensions: Compact 6 cm length, 1.5 cm diameter Storage space: Internal acrylic capsule (3.5 cm x ø 1 cm) Accessories: Includes 40cm lanyard for easy carrying _Farbe: Black, Silver, Gold (SORRY, NO COLOR CHOICE IS POSSIBLE)', 8.90, NULL, 1, NULL, 'Storage & Safes', 'artemis:headshop/verstecktresore,measure:60mm,material:Aluminium', true, false, false, NULL, '24010', 'Artemis', NULL, '2026-06-30 16:59:13.321968+00', false, NULL, NULL, NULL, 'https://www.artemisluzern.ch/ProductImage.ashx?src=v5&id=94e48248-ed3c-402e-bf6d-89b9da594994&w=414&h=414&ext=.jpg', '2026-06-30 15:48:07.964175+00', '2026-06-30 16:59:13.612986+00', NULL, NULL, NULL, 'standard', 'Headshop', 'storage-lifestyle-not-age-restricted (DRAFT, pending Treuhänder)', true, '{"length": "6 cm", "measure": "60mm", "diameter": "1.5 cm", "material": "Aluminium"}', '{"Length": "6 cm", "Diameter": "1.5 cm", "Material": "Aluminium"}', '{"class": 1.0, "category": 0.9, "description": 1.0}', 'null', '{"model": "gpt-oss:120b", "run_id": null, "recipe_version": "1.0"}', 'artemis', '94e48248-ed3c-402e-bf6d-89b9da594994', 'https://www.artemisluzern.ch/en/product/metall-dose-mit-halsband-pillendose-60mm-24010', 'en', 'headshop/verstecktresore', false, NULL);
INSERT INTO public.product_translations VALUES ('0a7afd51-dcc3-48a0-bc4d-b4f156404ad5', 'efce3594-f170-43b0-b37a-400b735b2163', 'en', 'Backwoods Blunt Authentic 5stk.', 'Backwoods cigars or backwoods blunts are specially imported from America to Switzerland. These special backwoods blunts are made in the Dominican Republic. The Backwoods Honey Berry are known from many celebrities who smoke these flavor cigars. Some like the backwood as it is, others like to add their own herbs to the backwoods, because they buy or rather have bought. You can easily roll these cigars apart and roll them back together again so that you have a perfect blunt. The Backwoods Honey Berry are very well packaged and are sewn airtight so that they do not dry out. The Backwoods Honey Berry are very well packaged and are sewn airtight so that they do not dry out.', 'source', false, '2026-06-30 15:10:50.004383+00', '2026-06-30 15:10:50.004385+00');
