INSERT INTO public.product_translations VALUES ('7e28fc23-de45-4d21-8597-bca4028daba5', '03df8138-b395-4bd0-a985-271c6e643fe2', 'en', 'G-Rollz Prerolled Blueberry Kookies  2 Stk.', 'Perfect enjoyment with CBD Blunt Cones from G-Rollz The Blunt Cones are 10.5 cm long and come in an airtight glass tube that contains two perfectly protected pieces. Thanks to the patented cone protection system from G-Rollz, the cones remain fresh and aromatic. They impress with first-class quality and a stylish look – ideal for headshop customers who value innovation and design. Whether it''s for relaxing evenings or special moments, these blunt cones take the smoking experience to the next level! High-quality blunt cones, developed in collaboration with cult stars Cheech and Chong Made from premium CBD flowers and canna-terpenes from the USA Tobacco and nicotine-free alternative for a pure smoking experience Flavor "Blueberry Biscuit" for sweet and fruity aroma variety', 'source', false, '2026-06-30 15:10:50.0093+00', '2026-06-30 15:10:50.009301+00');
INSERT INTO public.product_translations VALUES ('67bc7447-bc3d-43a2-a4d8-e70642c6e36c', 'de43a2f8-e9c4-44a9-baf8-717090427145', 'en', 'Chapo Blunt Hemp Wraps Cheri 2 stk.', 'Natural hemp wraps for the perfect blunt These high-quality hemp wraps are the ideal choice for anyone who wants to do without tobacco. Made from 100% natural hemp and completely free of tobacco, THC and nicotine, they offer a pure smoking experience. They are delivered in an airtight and resealable zip bag - so they stay fresh and aromatic. The wraps are perfect for headshop fans who value quality, naturalness and style. Try these flavorful wraps now and take your smoking ritual to the next level!', 'source', false, '2026-06-30 15:10:50.011434+00', '2026-06-30 15:10:50.011436+00');
INSERT INTO public.product_translations VALUES ('2bbc123e-d226-4148-ae95-a4fef7e0dd28', 'e21e618b-95d6-4a35-abd7-2a393055ab39', 'en', 'Juicy Jays Super Blunt Raspberry  23cm  1 Stk.', 'Huge blunt 23cm long and already brought into shape. Airtight packed in aluminum paper and again in a sturdy cardboard box. The best Super Blunt in the World!', 'source', false, '2026-06-30 15:10:50.013384+00', '2026-06-30 15:10:50.013387+00');
