INSERT INTO public.product_translations VALUES ('2b24352f-11a6-4da2-9b37-2aa9ab8bffd2', 'aa44ee40-219f-417c-8991-56cd43e42f7e', 'en', 'Elements King Size', 'Element Papers impress with the delicacy of the paper. Therefore, a good choice for every smoker! Elements are made of rice paper and burn with almost 0% ash. 100% pure rice paper with no chemicals, no pulp and NO hemp. To counter the trend and as a dedication to memories from the past, we have decided to revive the "elements" of smoking. Only a thin strip of natural sugar gum is used as a gluing point. The result is probably the best cigarette paper ever made by human hands.', 'source', false, '2026-06-30 15:10:50.020338+00', '2026-06-30 15:10:50.02034+00');
INSERT INTO public.product_translations VALUES ('b4cddafd-ea88-4f7e-996e-0684375b191d', '20efd458-ec72-4872-9d12-b6c30a34ea81', 'en', 'Gizeh DW kurz black', 'Extra fine leaves with a basis weight of 14 g/m² and a gum coating made of natural gum arabic, the sap of the acacia tree. The extra fine paper ensures pure and unadulterated enjoyment. It burns very slowly and goes out if you don''t pull on the self-rolled one. 2 rows with a total of 100 leaves are in a package with magnetic closure.', 'source', false, '2026-06-30 15:10:50.022111+00', '2026-06-30 15:10:50.022113+00');
INSERT INTO public.product_translations VALUES ('62bf7dcd-321e-4d0f-9410-6cf8399df6c7', 'e04faa71-9eb2-4501-8350-19e4557dbb71', 'en', 'Greengo King Size', 'These unbleached tobacco papers from ''Greengo'' come from wood from sustainable forestry cultivation. The Greengo Papers are not only eye-catching because of their pretty packaging, they are also unbleached and made with paper from a sustainable source. FSC label included. The fact that they are also ultra-thin and have a beautiful spiral pattern embossing is just the cherry on top of the sundae. Greengo Papers for a green smoke! The full tobacco aroma can fully develop, unaffected by bleach, etc.', 'source', false, '2026-06-30 15:10:50.023829+00', '2026-06-30 15:10:50.023831+00');
INSERT INTO public.product_translations VALUES ('22087f87-f8b5-4ed9-9b6a-6ac36088771d', '846597e7-0b4b-4bfd-be02-e1deb05963e9', 'en', 'Juicy Jays King Size Cannabis', 'The Juicy Papers and Rolls -with Flavor- are made of hemp paper and are available in different flavors with the respective printed ones. They simply taste good and look cool. Juicy Papes products are known for their distinctive and intense taste. Through a special, cost-intensive process, Juicy products are provided with a wide variety of flavors, so that the product has a fresh and intense taste that can even be tasted when smoked. An excellent change from the conventional papers.', 'source', false, '2026-06-30 15:10:50.025526+00', '2026-06-30 15:10:50.025528+00');
INSERT INTO public.product_translations VALUES ('8068d42f-67ac-4142-a164-4486fc49281d', '3b97e3da-6523-47de-85c7-0dc90f9d1ae3', 'en', 'Monkey King "King Size Slim & Filter" Blue Splash', 'Monkey King Papers – Aroma Edition: Fragrant papers with a real aroma effect The new Monkey King Papers with flavor variant really live up to their name: When you open the package, an intense, sweet scent immediately rises to your nose. No advertising ramblings – the aroma effect is immediately noticeable. The special highlight: After rubbing your buds, the typical weed smell often sticks to your fingers. With the Cookies Edition, you can easily cover this up. Rub your fingertips briefly on the packaging - and they take on the pleasant aroma scent of the papers. These papers not only offer high quality, but also a unique fragrance and user experience that clearly stands out from conventional papers. Perfect for those looking for that little bit extra.', 'source', false, '2026-06-30 15:10:50.027164+00', '2026-06-30 15:10:50.027166+00');
INSERT INTO public.product_translations VALUES ('2f329751-f6cb-4682-b0e1-343855fb7747', '1ce4f322-906c-4814-b9f7-9fa33ef07c33', 'en', 'OCB DW kurz Organic Hemp', 'Thin... really thin! OCB Papers is one of the most popular and well-known brands of French papers. A real hit in the thin paper sector. 100% natural made of hemp paper, vegan and unbleached. An absolutely new smoking experience!', 'source', false, '2026-06-30 15:10:50.028825+00', '2026-06-30 15:10:50.028827+00');
INSERT INTO public.product_translations VALUES ('e3d16b6d-9956-4e71-b35d-44c4e9c14a8c', '129d7be2-13be-4cfb-b3d8-1dfde74f4122', 'en', 'Raw KS Classic black Extra Fine', '100% natural and unbleached. An absolutely good smoking experience! Each package contains the organic RAW papers. Each package is printed on eco paper using a Japanese thermography process. The RAW Artesano Paperpack with paper, filter and mixing tray is the ideal companion for on the go. Its cover serves as a windbreak when turning as well as a tobacco pad. These papers burn very slowly and thus ensure long and easy smoking pleasure.', 'source', false, '2026-06-30 15:10:50.030531+00', '2026-06-30 15:10:50.030533+00');
INSERT INTO public.product_translations VALUES ('dc1839ee-2dc0-478d-86a8-e557c2dc5106', 'b742221b-f222-4b39-a49a-40b92379f201', 'en', 'OCB DW kurz schwarz', 'Thin... really thin! OCB Papers is one of the most popular and well-known brands of French papers. A real hit in the thin paper sector.', 'source', false, '2026-06-30 15:10:50.074911+00', '2026-06-30 15:10:50.074912+00');
INSERT INTO public.product_translations VALUES ('80025b08-f8c3-4134-b857-99fc6c6cb0a0', '4b0fa52e-8f8b-4282-adab-8e17d664b8c4', 'en', 'Highstore 20 Meter Premium Smoking Rolls', '?? 20 Meter Endless Papers Rolls – Ultra Thin Premium Quality ?? With the Endless Papers Rolls you get the longest papers in Switzerland: 20 meters of ultra-thin premium paper, perfect for endless sessions and maximum enjoyment. Thanks to its length, you decide how much you want to spin – with no limits, no refilling. 20 meters long – the longest smoking rolls in Switzerland Ultra Thin Paper (12.5 g/m²) – slow, even burning 44 mm width – ideal for custom turning Tasteless – pure enjoyment without annoying paper taste 16 rolls per box – ideal for heavy users or head shops Stylish design – eye-catching and modern in a high-store look The Endless Papers Rolls set new standards in terms of style and functionality. Whether for long sessions, creative creations or everyday use: With these smoking rolls you are at the forefront. Discover Swiss quality for real connoisseurs!', 'source', false, '2026-06-30 15:10:50.032186+00', '2026-06-30 15:10:50.032188+00');
INSERT INTO public.product_translations VALUES ('8bb7098e-5433-4dbb-8bd2-73f30a34a2f7', 'c66a00b1-64f9-4a2b-b42f-3a528e7f8e93', 'en', 'Rizla DW kurz orange', 'Rizla is one of "the" traditional company from France for cigarette papers. Thin paper with good burning behavior is a must for Rizla. Rizla Papers do not contain impregnations to improve the smoldering ability. On the one hand, this has the consequence that the self-rolled one goes out faster if you don''t pull it regularly. The adhesive strip is made of pure gum arabic. The Rizzla Orange are ideal if you don''t like the fact that your self-rolled cigarettes are constantly extinguished.', 'source', false, '2026-06-30 15:10:50.034082+00', '2026-06-30 15:10:50.034083+00');
INSERT INTO public.product_translations VALUES ('0d21f6b6-76cc-43bf-b692-4786ce7e0681', 'b145bffb-ea54-4336-b6ac-fc50d966321a', 'en', 'RS Rolls blau', 'The RS Rolls are very fine, wafer-thin cigarette papers made of rice with watermarks and natural gums, they have been around since 1984 and are produced in Italy.', 'source', false, '2026-06-30 15:10:50.035786+00', '2026-06-30 15:10:50.035788+00');
INSERT INTO public.product_translations VALUES ('7c96a731-dd66-4c0e-8b8e-cd7d062cdb50', '84a1d451-e756-4268-9040-7d7157b613b8', 'en', 'Shine 24K Gold Cone', 'The Shine 24K Gold Cones are an invention from the USA and are undoubtedly one of the most unusual items in our range. Gold is the status symbol par excellence and is widely regarded as a sign of prosperity. But not everyone is lucky enough to be rich. If you really want to make a splash, the Shine 24K Gold Cones are a real luxury accessory. The Shine 24K Gold Cones are great for making special moments (milestone birthday, New Year''s Eve, etc.) finally unforgettable. Give it to yourself or a friend and enjoy the unique feeling of smoking gold "in the pipe". The Shine 24K Gold Rolling Papers are coated with 24-carat gold on the outside. The gold used has 24 carats, because it ultimately ends up in your organism and coarse impurities (silver + copper) would pose a health hazard. The fine gold used could even be eaten... According to the statements of the first test smokers, the Gold Papers burn very slowly and evenly. Order a pack of Shine 24K Gold Cones today and you are guaranteed to be one of the first smokers in Switzerland to gild your mixture! The Shine 24K Gold Cones are already rolled, which means: just fill them and off you go.', 'source', false, '2026-06-30 15:10:50.037464+00', '2026-06-30 15:10:50.037466+00');
INSERT INTO public.product_translations VALUES ('1017c935-9673-428f-907b-dc527b62e84d', '5e56d0e9-f779-42ad-877f-a770c84bd3ee', 'en', 'Breit Dollar King Size', '''Breit'' Papers ''Dollar'' in king size format in the best ultra thin quality with natural gum coating. Uniform and slow, as well as almost residue-free combustion.', 'source', false, '2026-06-30 15:10:50.039252+00', '2026-06-30 15:10:50.039254+00');
INSERT INTO public.product_translations VALUES ('3b3e1541-7e7c-492b-bd3b-42ba9495538d', 'de1e3078-30f7-458d-a3e1-0278149ca19b', 'en', 'G-Rollz Banksy’s Graffiti Set 1  Lightly Dyed Pink KS Papers mit Bröselschale', 'Banksy''s graffiti on your papers – stylish and environmentally conscious! With the G-Rollz | Banksy''s Graffiti Set 1 you get Banksy''s iconic street art on your paper and tips booklets. A practical extra: Each booklet contains a foldable tray - perfect for on the go! The sustainable G-Rollz products combine cool design with environmental awareness. Check the authenticity of each booklet by scanning the verification code. Dimensions of the papers: length 11 cm, width 4.4 cm. A must-have for every smart shooting session! This series surprises with two different subjects that are chosen at random – surprise guaranteed. Per booklet you get: 50 unbleached, chlorine- and non-GMO papers 50 vegan tips A bamboo stick for darning', 'source', false, '2026-06-30 15:10:50.040905+00', '2026-06-30 15:10:50.040907+00');
INSERT INTO public.product_translations VALUES ('b4b2863d-709f-4d4d-86e3-ee6b10ce19e9', '109834d0-fa18-41a6-bec1-368235912464', 'en', 'Gummihülle für Smoking King Size Bob Marley', 'Gumi sleeve fits on all paper with king size format.', 'source', false, '2026-06-30 15:10:50.042625+00', '2026-06-30 15:10:50.042627+00');
INSERT INTO public.product_translations VALUES ('85744bf6-11a9-4c42-b809-9e686924e86c', '5ee14df8-7715-4891-9daa-bcf4117f635c', 'en', 'Air Filter  XHALE Buddy Mushroom grün', 'Discreet smoking made easy Forget about conspicuous clouds of cannabis that could attract the attention of neighbors or landlords. With this innovative air filter, you can exhale your smoke directly into the stylish mushroom. Thanks to a four-stage HEPA filter with nano-activated carbon, fragrances are effectively absorbed, and odor-free air flows out discreetly. Perfect for relaxed weed without unpleasant looks - on the go, at home or in the hotel. Technical highlights: 4-stage HEPA filter (100% recyclable) removes even the finest smoke particles ( Ergonomic mouthpiece made of food-grade silicone Portable and humorous mushroom design (6.35 cm diameter, 10.4 cm length) Durable filter for up to 500 puffs, easily replaceable (Item no. 453401-80) Protect yourself and others from secondhand smoke – environmentally friendly, efficient and in style!', 'source', false, '2026-06-30 15:10:50.044315+00', '2026-06-30 15:10:50.044317+00');
INSERT INTO public.product_translations VALUES ('1cabf4be-4732-49b8-9f5f-f34cd6171fc9', '7425e080-b416-4c46-bbad-7e8f8a6f0366', 'en', 'Filterpapier Amsterdam nicht perforiert', 'The filters are printed with food dye and are therefore completely safe for consumption. No color choice possible', 'source', false, '2026-06-30 15:10:50.046002+00', '2026-06-30 15:10:50.046003+00');
INSERT INTO public.product_translations VALUES ('55afd0fe-67fc-4136-8b49-b5ee2eb5742b', '295cbc2a-858e-48ef-ab16-75534e5a6aa2', 'en', 'Filterpapier Elements vorgerollt konisch 21stk', 'Elements Super Slim filters come in a practical transport box. One box contains 21 filters.', 'source', false, '2026-06-30 15:10:50.047711+00', '2026-06-30 15:10:50.047713+00');
INSERT INTO public.product_translations VALUES ('40cf4c78-81a1-417e-9cf3-50a9caa0ac56', 'de4b3c9e-0d3e-4a39-bb79-a4f7bd59fb6c', 'en', 'Black Leaf Füllhilf-Konsole Dollar', 'For all fans of cones: Very practical rolling tray from Black Leaf® especially for filling cones. And since cone fans are already a little lazy, you can finish two cones in one go! It''s really easy: Simply unfold the rolling tray, attach the accessories to the side, select the cone holder according to the cone size and load it with the appropriate cone. Insert the holders and cone into the openings of the tray, making sure that they are flush. Grind the herbs, mix with tobacco or a herbal mixture if necessary and tip onto the tray. Sweep herbs or mixture into the cone openings with the enclosed small whisk and press down with the cone maker tool. Then grasp the black holder and push it out from bottom to top and push out the filled cone - the perfect jay is ready! If you only want to fill a cone or use the Rolling Tray for conventional rolling or building, you can close the holes in the Rolling Tray with the sealing caps that are also included. The trays are printed with our popular Black Leaf® motifs.', 'source', false, '2026-06-30 15:10:50.049379+00', '2026-06-30 15:10:50.049381+00');
INSERT INTO public.product_translations VALUES ('c931d04f-c291-4b1c-b0e3-8b6ac8ac2a4e', '367b4edc-a12a-4b54-91fd-4a11d2b16ce0', 'en', 'Joint-Pack Amarantholz 110mm', 'Joints feel most comfortable in these beautifully natural, handmade joint tubes made of real wood from Black Leaf®. And are safely protected from moisture, crushing, crumbling and prying eyes. Precious wood from sustainable cultivation discreet Black Leaf engraving Flavour enhancement through wood aromas', 'source', false, '2026-06-30 15:10:50.051035+00', '2026-06-30 15:10:50.051037+00');
INSERT INTO public.product_translations VALUES ('7592d9b5-c77b-4f1c-a579-a13a55ee9287', '07b0425c-6a29-4f6d-86de-d9e7e313445f', 'en', 'Zigaretten-Hülsen 1000er Korona', 'Korona Cigarette Tubes - Box - 1000 Pieces Korona 550 box cigarette tubes made of high quality material at the best prices! The Korona tubes are individually removable and are perfect for rolling and stuffing cigarettes.', 'source', false, '2026-06-30 15:10:50.052707+00', '2026-06-30 15:10:50.052709+00');
INSERT INTO public.product_translations VALUES ('7a94a9cf-26a6-4c7f-8bf1-45339a2545e7', '403e109f-0220-452f-b2a1-e6be5221a5f7', 'en', 'Backwoods Blunt Bold 5 stk.', 'Intense aroma and full-bodied taste Backwoods Bold is the ideal choice for those looking for a bold and distinctive smoking experience. With its rustic look and intense tobacco notes, this variety delivers the typical backwoods character in an even more expressive variant. Earthy-spicy nuances give it an authentic profile that is particularly suitable for experienced connoisseurs. Rustic look and fresh pack for freshness As with all Backwoods cigars, the natural tobacco leaf provides the unmistakable look. Packed in a practical Fresh Pack, aroma and moisture are optimally preserved - perfect for on the go or in the humidor. Length: 11 cm Taste: sweet, spicy Ideal for quiet sessions or the evening Backwoods Bold offers you a pleasant but intense smoke with a full body – just right if you''re looking for more depth and character!', 'source', false, '2026-06-30 15:10:50.054517+00', '2026-06-30 15:10:50.054519+00');
INSERT INTO public.product_translations VALUES ('afd0f16d-dfd1-4049-9212-652a4e63df35', 'd4297c15-f5c6-4c50-aeb5-b4379ba7795f', 'en', 'Cyclones Blunt Clear mit Filter Tiki Tango Coconut 1 Stk.', 'With transparent paper conical pre-twisted blunt with Taste. Comes wrinkle-free in a plastic tube.', 'source', false, '2026-06-30 15:10:50.056301+00', '2026-06-30 15:10:50.056303+00');
INSERT INTO public.product_translations VALUES ('25cd598d-6b06-4457-845b-73376b1a3df4', 'adc365aa-40cf-41e2-964a-5225dc3100aa', 'en', 'G-Rollz Prerolled Mango  2 Stk.', 'Unique smoking experience and full aroma Enjoy an intense and aromatic smoking experience with the G-Rollz Terpene Infused Blunt Cones. These high-quality blunt cones are made from CBD flowers from the USA and enriched with premium canna-terpenes that provide an unadulterated taste and distinctive aroma. Tobacco and nicotine free: 100% free of tobacco and nicotine - ideal for those who prefer natural enjoyment without harmful additives. Alternative to traditional blunts, without compromising on taste. Innovative packaging and protection: Packaged in airtight glass tubes, freshness and aroma are optimally preserved. The patented G-Rollz Cone Protector protects against damage during transport and makes filling easy. King size for extra enjoyment: Length: 10.5 cm - perfect for long-lasting smoking pleasure with your favorite herbal blends. Two Blunt Cones per pack – convenient, fresh and ready to use. Positive features: Infused with USA ''Canna'' terpenes: Intense flavor and aroma. Tobacco and nicotine free: Pure enjoyment without harmful additives. Airtight packaging: freshness and aroma are preserved. Patented Cone Protector: Protection against damage and easy filling. King Size: Ideal for long-lasting smoking pleasure. Shelf-ready display: 12 glass tube sales unit, ideal for retail. Details: Material: Sheet material Packing: Glass tube Size: King Size Unit: 1 Carton: 12 tubes and 24 blunts', 'source', false, '2026-06-30 15:10:50.058014+00', '2026-06-30 15:10:50.058015+00');
INSERT INTO public.product_translations VALUES ('4da82325-7f68-4341-bb9e-a9adee71a272', '5b59a776-e160-4360-9443-75be2fd85417', 'en', 'Chapo Blunt Hemp Wraps El Patron 2 stk.', 'Natural hemp wraps for the perfect blunt These high-quality hemp wraps are the ideal choice for anyone who wants to do without tobacco. Made from 100% natural hemp and completely free of tobacco, THC and nicotine, they offer a pure smoking experience. They are delivered in an airtight and resealable zip bag - so they stay fresh and aromatic. The wraps are perfect for headshop fans who value quality, naturalness and style. Try these flavorful wraps now and take your smoking ritual to the next level!', 'source', false, '2026-06-30 15:10:50.059714+00', '2026-06-30 15:10:50.059716+00');
INSERT INTO public.product_translations VALUES ('f3ff5f96-7c70-41a9-83a2-b17a66254909', '3013c07b-0f98-4518-8420-f39d8d880046', 'en', 'Juicy Jays Super Blunt Tropical Passion  23cm  1 Stk.', 'Huge blunt 23cm long and already brought into shape. Airtight packed in aluminum paper and again in a sturdy cardboard box. The best Super Blunt in the World!', 'source', false, '2026-06-30 15:10:50.061413+00', '2026-06-30 15:10:50.061414+00');
INSERT INTO public.product_translations VALUES ('82fd9fce-2b93-48e0-8abe-ee6c40cd9524', 'd6dee67d-ab29-4ed6-81d2-f1088a5fcf1a', 'en', 'Drehmaschine Futurola Design 110mm', 'This Futurola Design lathe in king size length is almost an icon of machine-assisted cigarette production by hand The Futorola is made of plastic and the look of the lathe is absolutely stylish. Including free tamper with herb shovel', 'source', false, '2026-06-30 15:10:50.063052+00', '2026-06-30 15:10:50.063054+00');
INSERT INTO public.product_translations VALUES ('2e4689fd-eff4-44ed-9124-20691fb7f4a6', 'c56a15dc-7308-4203-acc3-018d79a523b3', 'en', 'Dollar King Size + Filter', 'Decadence... Yes, please! Long papers in super king size format with 100 US dollar motif. Benjamin Franklin is one of the founding fathers of the United States of America, with which he even made it onto the 100 dollar bill. Was he also a stoner? No idea! The Super King Size Papers are made of unbleached hemp paper and printed with soy ink. This is how burning dollars is really fun!!', 'source', false, '2026-06-30 15:10:50.064731+00', '2026-06-30 15:10:50.064732+00');
INSERT INTO public.product_translations VALUES ('0241b183-1c37-40c9-be7a-ef4616b13286', 'fa7b5a31-ef52-4cf9-a2b2-0667de9599f4', 'en', 'Elements King Size Phantom Slim', 'Elements Phantom King Size Slim – Ultra-thin, exclusive & almost invisible Experience the purest smoking experience with the Elements Phantom King Size Slim - probably the thinnest papers from Elements. Around 20% thinner than standard models, they burn extra slowly and evenly and are almost tasteless - for unadulterated enjoyment of your herbs or tobacco mixture. This exclusive special edition is only produced in small editions and is currently available almost exclusively in the USA - a real collector''s item for paper fans. Highlights: Ultra-thin rice paper (approx. 20% thinner than standard) Exclusive Limited Edition – hard to get King Size Slim Format (110 × 44 mm) Almost tasteless - ideal for pure enjoyment Natural Acacia Gum Slow, even burning without canoeing Made in Spain – Original Elements quality', 'source', false, '2026-06-30 15:10:50.066417+00', '2026-06-30 15:10:50.066418+00');
INSERT INTO public.product_translations VALUES ('f226f85e-0b2b-430e-a105-399c114096e1', 'a22b4a4b-aeb6-4b02-96d5-039c15652b28', 'en', 'Gizeh King Size', 'Extra fine, leaflets with a basis weight of 14.0 g/m² and a gum coating made of natural gum arabic, the sap of the acacia tree. The extra fine paper ensures pure and unadulterated enjoyment., the width corresponds to the King Size Slim format. The paper burns very slowly and goes out if you don''t pull the self-rolled one. And of course, the packs are fully recyclable.', 'source', false, '2026-06-30 15:10:50.068071+00', '2026-06-30 15:10:50.068073+00');
INSERT INTO public.product_translations VALUES ('3e0563be-4d56-4f33-829b-5e571b595b54', 'c6f09ccc-a71f-43f2-b5b5-04519467dd6b', 'en', 'Greengo King Size Slim', 'These unbleached tobacco papers from ''Greengo'' come from wood from sustainable forestry cultivation. The Greengo Papers are not only eye-catching because of their pretty packaging, they are also unbleached and made with paper from a sustainable source. FSC label included. The fact that they are also ultra-thin and have a beautiful spiral pattern embossing is just the cherry on top of the sundae. Greengo Papers for a green smoke! The full tobacco aroma can fully develop, unaffected by bleach, etc.', 'source', false, '2026-06-30 15:10:50.069782+00', '2026-06-30 15:10:50.069784+00');
INSERT INTO public.product_translations VALUES ('f1152084-824c-472e-8d58-f485c60ae92d', '7e277abe-8996-4fef-aa15-24963b0289de', 'en', 'Juicy Jays Rolls Apple', 'The Juicy Papers and Rolls -with Flavor- are made of hemp paper and are available in different flavors with the respective printed ones. They simply taste good and look cool. Juicy Papes products are known for their distinctive and intense taste. Through a special, cost-intensive process, Juicy products are provided with a wide variety of flavors, so that the product has a fresh and intense taste that can even be tasted when smoked. An excellent change from the conventional papers.', 'source', false, '2026-06-30 15:10:50.071484+00', '2026-06-30 15:10:50.071486+00');
INSERT INTO public.product_translations VALUES ('0cf20da0-d278-47d0-90c2-c57e8b525140', 'ad1c6174-f561-4bc6-94a6-dade6d769115', 'en', 'Monkey King "King Size Slim & Filter" Bubble Gum', 'Monkey King Papers – Aroma Edition: Fragrant papers with a real aroma effect The new Monkey King Papers with flavor variant really live up to their name: When you open the package, an intense, sweet scent immediately rises to your nose. No advertising ramblings – the aroma effect is immediately noticeable. The special highlight: After rubbing your buds, the typical weed smell often sticks to your fingers. With the Cookies Edition, you can easily cover this up. Rub your fingertips briefly on the packaging - and they take on the pleasant aroma scent of the papers. These papers not only offer high quality, but also a unique fragrance and user experience that clearly stands out from conventional papers. Perfect for those looking for that little bit extra.', 'source', false, '2026-06-30 15:10:50.073149+00', '2026-06-30 15:10:50.073151+00');
INSERT INTO public.product_translations VALUES ('7114acba-f471-48fe-bb3c-76c6ecd7e746', '786f93f4-a41c-4741-a470-3686e188113e', 'en', 'Raw KS slim Artesano Classic brown mit Filter und Mischschale', '100% natural and unbleached. An absolutely good smoking experience! Each package contains the organic RAW papers. Each package is printed on eco paper using a Japanese thermography process. The RAW Artesano Paperpack with paper, filter and mixing tray is the ideal companion for on the go. Its cover serves as a windbreak when turning as well as a tobacco pad. These papers burn very slowly and thus ensure long and easy smoking pleasure.', 'source', false, '2026-06-30 15:10:50.076592+00', '2026-06-30 15:10:50.076594+00');
INSERT INTO public.product_translations VALUES ('1511d42b-ebe7-4ecc-b6d8-6c500f175564', '569420e3-2c17-4ab3-8e5e-a9de68e6f07c', 'en', 'Old School Papers', 'Expand your world of smoking pleasure with the Metal Eco Box with R36 Roll! In the beautiful world of smoking pleasure, there is a hidden treasure that you should definitely discover - the Metal Eco Box with R44 Roll. This stylish wooden box is more than just storage. It is a statement, an embodiment of your unique taste and awareness of nature. With a replacement paper roll and the Eco Metal Box R36, you don''t just get an item, but a lifestyle accessory that elevates smoking to a true art and you also contribute something to nature! The paper roll in this box is no ordinary paper. It is 100% natural and without additives. Each paper is perfectly proportioned to take your smoking pleasure to the next level. The roll container width of 4.6 cm not only offers space for the R36 roll, but also for your creativity and anticipation of unforgettable joints. The elegant design of this metal eco box emphasizes your uniqueness and attention to detail and nature. With the Metal Eco Box with R36 Wheel, you are not just carrying an object with you, but a piece of your personality.', 'source', false, '2026-06-30 15:10:50.078327+00', '2026-06-30 15:10:50.078329+00');
INSERT INTO public.product_translations VALUES ('db0bf016-3a94-4c82-945c-82e09c3365b6', 'cf175a98-6082-4095-b11c-b21ca7ab5b28', 'en', 'Rizla DW kurz silver', 'Rizla is one of "the" traditional company from France for cigarette papers. Thin paper with good burning behavior is a must for Rizla. Rizla Papers do not contain impregnations to improve the smoldering ability. On the one hand, this has the consequence that the self-rolled one goes out faster if you don''t pull it regularly. The adhesive strip is made of pure gum arabic. Probably the thinnest papers from Rizla', 'source', false, '2026-06-30 15:10:50.079987+00', '2026-06-30 15:10:50.079989+00');
INSERT INTO public.product_translations VALUES ('8f788718-0420-4c34-9715-5b78a4a56cbf', 'f3db0f7b-745a-4397-84a6-9e1f0b8fb1de', 'en', 'RS Rolls grün', 'The RS Rolls are very fine, wafer-thin cigarette papers made of rice with watermarks and natural gums, they have been around since 1984 and are produced in Italy.', 'source', false, '2026-06-30 15:10:50.081698+00', '2026-06-30 15:10:50.081699+00');
INSERT INTO public.product_translations VALUES ('f4405772-434f-4842-90d4-f47463ae5c59', '9c23d730-dd35-4d56-9da5-b66d6a887855', 'en', 'Purize King Size brown Slim', 'The Purize King Size Slim Papers "Brown" are the perfect companion for anyone looking for high-quality and tasteless rolling papers. Unbleached and made from natural wood fibres, they offer a clean smoking experience with the best burning behaviour. Thanks to the natural gum coating and a paper thickness of only 13 g/m², they are particularly thin and minimise any impairment of taste. Their slight transparency underlines the quality of the material. Technical details: Length: 10.8 cm Width: 4.4 cm Number of sheets per pack: 33 pcs. Raw material: Natural hemp Advantages at a glance: Optimal burning behavior without annoying additives Tasteless material for unadulterated enjoyment Sustainably produced quality for modern smokers', 'source', false, '2026-06-30 15:10:50.083388+00', '2026-06-30 15:10:50.08339+00');
INSERT INTO public.product_translations VALUES ('703bcd6e-dcb3-4156-b959-eb4a44f13755', '0c8a7b62-bd58-49ab-b4cf-d7d7f01a1728', 'en', 'G-Rollz Banksy’s Graffiti Set 2  Lightly Dyed Pink KS Papers mit Bröselschale', 'Banksy''s graffiti on your papers – stylish and environmentally conscious! With the G-Rollz | Banksy''s Graffiti Set 1 you get Banksy''s iconic street art on your paper and tips booklets. A practical extra: Each booklet contains a foldable tray - perfect for on the go! The sustainable G-Rollz products combine cool design with environmental awareness. Check the authenticity of each booklet by scanning the verification code. Dimensions of the papers: length 11 cm, width 4.4 cm. A must-have for every smart shooting session! This series surprises with two different subjects that are chosen at random – surprise guaranteed. Per booklet you get: 50 unbleached, chlorine- and non-GMO papers 50 vegan tips A bamboo stick for darning', 'source', false, '2026-06-30 15:10:50.08508+00', '2026-06-30 15:10:50.085082+00');
INSERT INTO public.product_translations VALUES ('4cd3a24f-163f-419e-be0d-8f7d0617d40f', '9a69b0c6-1054-4615-8356-3c5dd73b42f9', 'en', 'Gummihülle für Smoking King Size Hanfblatt grün', 'Gumi sleeve fits on all paper with king size format.', 'source', false, '2026-06-30 15:10:50.08681+00', '2026-06-30 15:10:50.086812+00');
INSERT INTO public.product_translations VALUES ('63793c0a-4df0-443c-af9c-2bba86795fd0', 'be782448-1e4a-4d0d-81c6-5b2bb9abdc16', 'en', 'Black Leaf Aufkleber für Glastips', 'Perfect fixation for glass filters Do you use glass filters in your joints and struggle with slipping or falling out? Black Leaf''s® food-grade adhesive strips are the ideal solution! Simply attach the paper directly to the glass filter - for optimal hold and relaxed smoking. The roll contains 50 sticky stickers that are perfectly pre-portioned. Thanks to the practical slot in the packaging, you can peel off the stickers individually - quickly and easily. The adhesive strips are suitable for glass filters with a diameter of 6 mm, 7 mm or 8 mm. A must-have for your smokeware collection! No slipping or falling out Easy to use and stylish', 'source', false, '2026-06-30 15:10:50.088521+00', '2026-06-30 15:10:50.088522+00');
INSERT INTO public.product_translations VALUES ('0cb30c63-3e37-4ac6-b8c3-8d103eebaa89', '720b4a79-fab0-41d8-8d6f-b39a789d723a', 'en', 'Aktivkohlefilter actiTube 8mm 100stk', 'Reduces the pollution of the respiratory tract every puff tastes pleasantly cool, gentle and dry No clogging No outflow of condensation Why activated carbon filters and still works: When smoking with Tune activated carbon filter, only a certain amount of active substances or pollutants adheres to the surface of the lungs with each puff, and residual smoke is always exhaled. Therefore, the composition of the inhaled smoke is extremely important. In the case of THC-containing smoke, activated carbon mainly filters the water-soluble substances from the smoke and thus changes the condensate/THC ratio in the direction of THC. With the Tune products, the pollutant content per THC is lower. The Tune activated carbon filter takes the damage out of the fabric. Tune recommends smoking slowly and in small puffs. Details: Diameter 8mm Length 35mm Box 100pcs.', 'source', false, '2026-06-30 15:10:50.08939+00', '2026-06-30 15:10:50.089392+00');
INSERT INTO public.product_translations VALUES ('058cfcb8-4ecf-4db3-9a59-dd296c997ca0', 'b7398d74-0c4f-4111-b783-b2261207811c', 'en', 'Adapter NS14 Plaisir Spezial Spirale Diverse 29.00', 'A glass NS14 adapter with a special spiral design, suitable for 14 mm bowl openings.', 'source', false, '2026-06-30 15:48:07.929106+00', '2026-06-30 15:48:07.929108+00');
INSERT INTO public.product_translations VALUES ('d214daf7-afdb-4ac8-9983-83d0c2688f0c', '722bd3d7-32a5-4b67-98c5-32b8a3b529b2', 'en', 'Greenfire Black Cream Haschisch 9g', 'The Artemis Greenfire Black Cream Hash offers a great smoking experience with a sweet, spicy scent and a unique creamy sticky consistency. With a high cannabinoid content of 31%, it fully convinces CBD lovers. Let yourself be gently and with a delicious scent floating into the orient of good hashish!', 'source', false, '2026-06-30 15:48:07.93262+00', '2026-06-30 15:48:07.932622+00');
INSERT INTO public.product_translations VALUES ('5c77a281-0933-4819-82c2-cd8c0872062e', '889df711-dbd6-447b-874d-2449ea66d616', 'en', 'Hash Bunnies - Premium Swiss CBD Hash - 4x Filtre - 7g', 'With the Hash Bunnies - Golden Piatella, we present you the absolute flagship of the art of hashing: A creamy, almost melting CBD hash produced by the elaborate Piatella Cure technique - inspired by traditional Temple Ball craftsmanship and state-of-the-art Swiss innovation and precision. This golden hash is not pressed, but matured - slowly, controlled, with perfect moisture. The result: an incredibly aromatic, buttery masterpiece for true connoisseurs.', 'source', false, '2026-06-30 15:48:07.955735+00', '2026-06-30 15:48:07.955737+00');
INSERT INTO public.product_translations VALUES ('0fa7ccbe-837c-4cdf-8284-b0a2913c3251', 'cac33eaa-3408-4c1b-bb35-d46f623a18b2', 'en', 'Hash Gang Jamaican Pollen 4.20gr.', 'Jamaican Pollen is an exquisite pollen, intense and fruity-sweet in taste and resinous. Pure Caribbean! It is soft and pleasant to work with and, with its high CBD content, it is just the right product to give your hashish joint the decisive kick.', 'source', false, '2026-06-30 15:48:07.998442+00', '2026-06-30 15:48:07.998444+00');
INSERT INTO public.product_translations VALUES ('67c52ed8-6347-48a9-a34c-efe3629633c0', '53188f6f-b602-4f95-bcfb-6b58cbd4db03', 'en', 'VOZOL Gear S 4000 KIT Space Gray / Blue Razz Ice', 'The well-known device manufacturer Vozol has made a precision landing with the kit of the Gear S 4000. The easiest way to vape is the disposable e-cigarette. The Vozol Gear S 4000 scores with a chic and compact body, which can be taken anywhere thanks to the carabiner. Due to its small size, the Gear S 4000 can also be taken into your pocket or handbag. Since the body of the Vozol is made of 65% PCR material and anodized aluminum, this disposable vape is very robust. In addition, a removable silicone cap ensures that no dirt or dust gets into your mouthpiece. As we all know, looks are not everything, which is why the Vozol Gear S 4000 also convinces with a VAMT mesh coil inside. This coil and the advanced technology of the high-quality airflow design make the Gear S 4000 very pleasant to vape. This makes the taste more aromatic and natural. According to the manufacturer, about 4000* trains are to be expected. (*without guarantee) The 500mAh battery ensures super fast charging, so your disposable cigarette can be used again right away. The disposable vape is filled with 20MG/ML nicotine salt and aromatic liquid. The Vozol Gear S 4000 is available from us in different flavors. So everyone gets their preferred flavor. The Vozol Gear S 4000 is a powerful and reliable disposable vape. This makes it suitable for anyone who wants an intense and long-lasting vaping experience. The Gear S 4000 is a disposable product and cannot be refilled. If the e-cigarette is empty, recycle the empty vape properly. You can return empty e-cigarettes to any point of sale or directly to us.', 'source', false, '2026-06-30 15:48:07.934854+00', '2026-06-30 15:48:07.934857+00');
INSERT INTO public.product_translations VALUES ('7bc37a02-7750-4b77-b5ad-17817ddff260', 'f345d543-22c9-4727-baa1-51b21122c9d1', 'en', 'c Safes Safe-Box 5XL mit Magnet 255x330x130mm', 'The ''Secret Safes'' Safe Box with Magnet is made of high-resistance ABS plastic with stainless steel pivot bolts and is lined with foam on the inside to protect valuables. This ''Secret Safe'' can be securely attached under the trolley when travelling due to the magnets and is waterproof and airtight thanks to the O-rubber seal, so your valuables are safe from rain and mud. But it can also be inconspicuously fixed at home behind household appliances and many other metallic objects and is thus protected from thieves or prying eyes. Made in the USA.', 'source', false, '2026-06-30 15:48:07.937139+00', '2026-06-30 15:48:07.937141+00');
INSERT INTO public.product_translations VALUES ('5f10a6fb-f6ba-456a-a195-9b462d2b9a5f', '3c946f75-7c91-4188-94c5-bc05a366d8d0', 'en', 'Glas-Kopf NS14 konisch 25mm Ø', '''Black Leaf'' Glasshillum with standard cut NS14 / 14,5mm. The Shillum is 240-250mm long and can be shortened to the appropriate length.', 'source', false, '2026-06-30 15:48:07.939214+00', '2026-06-30 15:48:07.939215+00');
INSERT INTO public.product_translations VALUES ('2177d728-8761-4396-8550-05deee892c23', 'fa235d59-1ec8-488f-894e-1e97feae3ced', 'en', 'Greenfire Red Sputnik Haschisch 9g', 'The Artemis Red Sputnik is Swissmade and has a brown-dark red color. It convinces with gentle aromas and an earthy taste. With its high CBD content of around 32% and fine taste, this Sputnik will take you on a gentle journey into the indica galaxy!', 'source', false, '2026-06-30 15:48:07.941189+00', '2026-06-30 15:48:07.941191+00');
INSERT INTO public.product_translations VALUES ('824a164c-496a-4070-8283-e80ba7cb04b8', '1dc1f3f8-88f7-4e0a-843d-f2addd4a1f06', 'en', 'VOZOL Gear S 4000 KIT Space Grey / Strawberry Ice Cream', 'The well-known device manufacturer Vozol has made a precision landing with the kit of the Gear S 4000. The easiest way to vape is the disposable e-cigarette. The Vozol Gear S 4000 scores with a chic and compact body, which can be taken anywhere thanks to the carabiner. Due to its small size, the Gear S 4000 can also be taken into your pocket or handbag. Since the body of the Vozol is made of 65% PCR material and anodized aluminum, this disposable vape is very robust. In addition, a removable silicone cap ensures that no dirt or dust gets into your mouthpiece. As we all know, looks are not everything, which is why the Vozol Gear S 4000 also convinces with a VAMT mesh coil inside. This coil and the advanced technology of the high-quality airflow design make the Gear S 4000 very pleasant to vape. This makes the taste more aromatic and natural. According to the manufacturer, about 4000* trains are to be expected. (*without guarantee) The 500mAh battery ensures super fast charging, so your disposable cigarette can be used again right away. The disposable vape is filled with 20MG/ML nicotine salt and aromatic liquid. The Vozol Gear S 4000 is available from us in different flavors. So everyone gets their preferred flavor. The Vozol Gear S 4000 is a powerful and reliable disposable vape. This makes it suitable for anyone who wants an intense and long-lasting vaping experience. The Gear S 4000 is a disposable product and cannot be refilled. If the e-cigarette is empty, recycle the empty vape properly. You can return empty e-cigarettes to any point of sale or directly to us.', 'source', false, '2026-06-30 15:48:07.943078+00', '2026-06-30 15:48:07.94308+00');
INSERT INTO public.product_translations VALUES ('3b92d6be-ff01-464f-89da-d28cd76952b7', 'e9b18289-b49b-4777-b3f3-5fb8a035bd21', 'en', 'c Safes Safe-Box 7XL mit Magnet 430x380x180mm', 'The ''Secret Safes'' Safe Box with Magnet is made of high-resistance ABS plastic with stainless steel pivot bolts and is lined with foam on the inside to protect valuables. This ''Secret Safe'' can be securely attached under the trolley when travelling due to the magnets and is waterproof and airtight thanks to the O-rubber seal, so your valuables are safe from rain and mud. But it can also be inconspicuously fixed at home behind household appliances and many other metallic objects and is thus protected from thieves or prying eyes. Made in the USA.', 'source', false, '2026-06-30 15:48:07.944934+00', '2026-06-30 15:48:07.944936+00');
