INSERT INTO public.product_translations VALUES ('b182241b-155e-4027-bab3-f4c30a4e0ece', 'f7cdbf74-2bf4-479e-848a-f5653b7ae845', 'en', 'STALIN PhoneBag Kunstleder Big schwarz  Carbon Look 215x145mm', 'The STALIN PhoneBag – for espionage-proof privacy! Product details: Big+ faux leather – carbon look with dark grey stitching The undisputed bestseller among shielding mobile phone cases is handmade in Germany. All bags are made of high-quality materials and are subjected to a functional test before delivery. The STALIN, an indispensable gadget for you and your data. Scientifically tested and certified, this quality product ensures that maximum protection against espionage is achieved. All connections and signals - GPRS, WLAN, Bluetooth, RFID, NFR, etc. - are blocked neither your location can be located nor your conversations tapped Close-up scans or capturing mobile devices through area scans are impossible KeylessGo car thefts are unsuccessful High-frequency electromagnetic radiation and low-frequency alternating electric fields are shielded Please note: In order for all these protective measures to work properly, the bag must be closed! In the end, the latest and state-of-the-art technology ensures that the STALIN mobile phone cases protect your privacy in the best possible way. The structure and materials have been specially developed for this purpose. The inner lining consists of a multi-layer fleece that contains multi-layered shielding fiber panels. An enormously dense and highly metallized polyamide fabric forms the basis for this special nonwoven. In addition, the closures are triple magnetic locking systems and are mounted on the inside. As a result, they provide reliable protection and can withstand even heavy use. And the cover of the STALIN - optionally made of real or artificial leather - rounds off your safety zone completely. The result: When closed, all contact with the outside world is blocked and signals are made unrecognizable.', 'source', false, '2026-06-30 15:48:07.980668+00', '2026-06-30 15:48:07.98067+00');
