INSERT INTO public.product_translations VALUES ('5258b456-d97a-4538-88fb-85278d1a1589', '751dada1-8ca2-40f8-a3d1-1ba475249fdd', 'en', 'Tresor Autoschlüssel', 'Deceptively real car key safe – your secret valuables hiding place! Imagine being able to store your small valuables in a place that no one would ever suspect. The car key safe is the perfect solution to keep your secrets safe without anyone raising suspicions. This key safe is not only a safe place to store it, but also a true masterpiece of camouflage. From the outside, it looks exactly like a normal car key. No one will ever suspect that there is anything valuable hidden in it. With dimensions of just 30x50x10mm, this safe is small and handy. You can easily carry it in your pocket or store it in a safe place. Whether at home, in the office or on the road, this key safe is always ready for use. Operation is child''s play. You can open the safe by pulling the key apart and removing the rear lid. Inside, you''ll find a small space for small valuables like jewelry, one or two banknotes, or important notes. The camouflage of this safe is so convincing that even a professional thief would never suspect that valuables are hidden here. This makes it the ideal choice for keeping your secrets and valuables safe. Protect your valuables from prying eyes and unwanted access with this ingenious car key safe.', 'source', false, '2026-06-30 15:48:07.994942+00', '2026-06-30 15:48:07.994944+00');
INSERT INTO public.product_translations VALUES ('897f5836-46f6-454e-bf73-5865549f6035', '9e7095c8-2e14-4ae5-8fc7-338d0f4b6dda', 'en', 'VOZOL SWITCH 600 Kit schwarz Blackberry Ice', 'The Switch 600 kit comes with the Switch 600 device and matching a pod with the flavor. Depending on the color, you will get a different taste. The Switch 600 kit can be recharged and the pods are simply replaced after they are empty. The brand specializes in disposable vaping devices and has been gaining popularity in Europe for some time now. Vozol appliances impress above all with their quality, functionality and variety of tastes - no less than 17 different tastes are available for you to choose from. Apart from that, Vozol is the perfect start for smokers who want to switch to vaping.', 'source', false, '2026-06-30 15:48:08.000234+00', '2026-06-30 15:48:08.000236+00');
INSERT INTO public.product_translations VALUES ('67a1077b-e100-481d-991f-b8b5c5866eb6', '39165d55-b2d5-4c37-a577-3a3614e09650', 'en', 'Tresor AXE Deo Gold Temptation', 'AXE Stash Safe - Your personal secret hiding place in deodorant format! You probably know AXE as a brand for refreshing deodorants. But now there is the AXE Stash Safe, a clever and inconspicuous stash in deodorant format. Why the AXE Stash Safe? Imagine being able to store your valuables in a place no one would ever suspect - in your deodorant! The AXE Stash Safe looks like an ordinary deodorant, but inside it hides a secret compartment that measures 8 cm high and 3.5 cm in diameter. That''s enough to keep your little treasures safe. Whether you have cash, jewelry, important documents, or other valuable items you want to protect, the AXE Cache Safe has you covered. No one would ever think of looking for valuables in your deodorant.', 'source', false, '2026-06-30 15:48:08.002059+00', '2026-06-30 15:48:08.002061+00');
INSERT INTO public.product_translations VALUES ('1c043eb4-63a9-4882-a59f-e6d45a29a5bd', '3759e85e-0389-4c62-9e0c-8999fd92203d', 'en', 'Glas-Steckkopf NS14 konisch 16mm Ø Boobs', 'Plug-in head with standard grind 14 You haven''t seen a design like this for a long time! It''s almost too bad to smoke with it.', 'source', false, '2026-06-30 15:48:08.003826+00', '2026-06-30 15:48:08.003828+00');
INSERT INTO public.product_translations VALUES ('277f95e0-d51f-487f-a37c-9f42efe2ffe6', '0fec64fb-4fb6-45b6-b5a4-300488670460', 'en', 'Hash Gang Manali Cream 4.20gr.', 'Like Charras, Manali Cream has been known for decades as one of the best hashish strains in the world. Its soft, creamy consistency and intense smell will delight all Black Afghan fans. The extremely high concentration of CBD will instantly relax you and throw you into chill mode. Closer to the original is not possible - an experience that is second to none!', 'source', false, '2026-06-30 15:48:08.005601+00', '2026-06-30 15:48:08.005603+00');
