INSERT INTO public.product_translations VALUES ('2345195f-8c4f-46c1-a96c-b8061157a61c', '8d0f6021-7152-4683-a605-af9f57fd9382', 'en', 'Hash Gang Temple Ball 4.20gr.', 'The Temple Ball is one of the best CBD hashish currently available and belongs to the SUPREME line of the Hash Gang. As the name suggests, it has the shape of a classic black temple ball, according to the original, handcrafted by our experts. You can easily roll it into a "worm" that you can place in the center of your joint. It smells wonderfully authentic when it is slightly heated and tastes so similar to the original that there is a risk of confusion. A real success of our favorite Swiss producer!', 'source', false, '2026-06-30 15:48:08.012607+00', '2026-06-30 15:48:08.012608+00');
