INSERT INTO public.product_translations VALUES ('0cb7b0c1-300e-472f-a2ba-8899690ad538', '5e35e800-3535-4171-9e19-36eb3e5a8d2c', 'en', 'Glas-Steckkopf NS14 konisch 28mm Ø Wirbel Türkis', 'Strikingly beautiful, artistically handmade herbal head from ''Black Leaf'' made of multi-coloured borosilicate glass. A sieve is already integrated. In addition, the glass bowl has a handle as well as a roll-stopper in the shape of a glass ball, which contains a cute mushroom. By the way, the ''Black Leaf'' logo is discreetly engraved on the cut. ALMOST too good to smoke with...', 'source', false, '2026-06-30 15:48:08.017869+00', '2026-06-30 15:48:08.017871+00');
INSERT INTO public.product_translations VALUES ('03c27212-ad27-473e-b887-8102851ddb40', '12bdca5e-2d42-424a-8529-f1320e61f8d0', 'en', 'Lama Weed Trichoselect D Sweet Dreams 5g', 'Trichoselect D – Sweet Dreams (5g) by Lamaweed Swiss hash indulgence for relaxing nights Experience a classic hash pleasure as it should be with Trichoselect D – Sweet Dreams by Lamaweed: Dark, soft, aromatic. Made in Switzerland, in harmony with nature, this CBD hash convinces with its pleasant consistency and excellent processing quality - without any tobacco or synthetic additives. The slightly soft structure makes it particularly easy to use - whether rolled, in a vaporizer or in a pipe. The aroma is earthy-spicy with gentle notes that perfectly match the relaxed effect. With less than 1% THC, Sweet Dreams remains perfectly legal and is ideal for enjoying in the evening. Produced in Switzerland: quality from controlled cultivation Dark brown color & soft consistency: easy to mold and versatile Free of tobacco & additives: natural product 5 g pack: high-quality hash at a fair price', 'source', false, '2026-06-30 15:48:08.018901+00', '2026-06-30 15:48:08.018903+00');
